"use strict";(self.webpackChunkducnguyen_96_github_io=self.webpackChunkducnguyen_96_github_io||[]).push([[3836],{4641:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"/2023/what-is-finalhandler","metadata":{"permalink":"/en/blog/2023/what-is-finalhandler","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2023/what-is-finalhandler.md","source":"@site/blog/2023/what-is-finalhandler.md","title":"finalhandler l\xe0 g\xec? c\xf3 n\xean s\u1eed d\u1ee5ng n\xf3?","description":"","date":"2023-12-20T13:38:27.000Z","formattedDate":"December 20, 2023","tags":[{"label":"nodejs","permalink":"/en/blog/tags/nodejs"},{"label":"js","permalink":"/en/blog/tags/js"},{"label":"Networking Programming","permalink":"/en/blog/tags/networking-programming"}],"readingTime":0,"hasTruncateMarker":false,"authors":[{"name":"\u0110\u1ee9c Nguy\u1ec5n","title":"Developer, Translator","url":"https://github.com/ducnguyen96","imageURL":"https://avatars.githubusercontent.com/u/47471616?v=4","key":"ducnguyen96"}],"frontMatter":{"title":"finalhandler l\xe0 g\xec? c\xf3 n\xean s\u1eed d\u1ee5ng n\xf3?","authors":["ducnguyen96"],"tags":["nodejs","js","Networking Programming"],"hide_table_of_contents":false},"unlisted":false,"nextItem":{"title":"H\xe3y ch\xfa \xfd khi s\u1eed d\u1ee5ng mutexes trong Go.","permalink":"/en/blog/2018/beware-of-copying-mutexes-in-go"}},"content":""},{"id":"/2018/beware-of-copying-mutexes-in-go","metadata":{"permalink":"/en/blog/2018/beware-of-copying-mutexes-in-go","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2018/beware-of-copying-mutexes-in-go.md","source":"@site/blog/2018/beware-of-copying-mutexes-in-go.md","title":"H\xe3y ch\xfa \xfd khi s\u1eed d\u1ee5ng mutexes trong Go.","description":"H\xe3y ch\xfa \xfd khi s\u1eed d\u1ee5ng mutexes trong Go..","date":"2023-12-15T11:34:06.000Z","formattedDate":"December 15, 2023","tags":[{"label":"Go","permalink":"/en/blog/tags/go"},{"label":"Concurrency","permalink":"/en/blog/tags/concurrency"}],"readingTime":3.515,"hasTruncateMarker":false,"authors":[{"name":"Eli Bendersky","title":"Developer","url":"https://eli.thegreenplace.net","imageURL":"https://avatars.githubusercontent.com/u/1130906?v=4","key":"eliben"},{"name":"\u0110\u1ee9c Nguy\u1ec5n","title":"Developer, Translator","url":"https://github.com/ducnguyen96","imageURL":"https://avatars.githubusercontent.com/u/47471616?v=4","key":"ducnguyen96"}],"frontMatter":{"title":"H\xe3y ch\xfa \xfd khi s\u1eed d\u1ee5ng mutexes trong Go.","description":"H\xe3y ch\xfa \xfd khi s\u1eed d\u1ee5ng mutexes trong Go..","authors":["eliben","ducnguyen96"],"tags":["Go","Concurrency"],"hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"finalhandler l\xe0 g\xec? c\xf3 n\xean s\u1eed d\u1ee5ng n\xf3?","permalink":"/en/blog/2023/what-is-finalhandler"},"nextItem":{"title":"H\xe0m s\u1ed1 bi\u1ec3u th\u1ecb m\u1ed1i t\u01b0\u01a1ng quan gi\u1eefa effort b\u1ecf ra v\xe0 l\u1ee3i \xedch khi s\u1eed d\u1ee5ng dependencies trong c\xe1c d\u1ef1 \xe1n ph\u1ea7n m\u1ec1m.","permalink":"/en/blog/2017/benefits-of-dependencies-in-software-projects-as-a-function-of-effort"}},"content":"Gi\u1ea3 s\u1eed ta c\xf3 m\u1ed9t `struct ch\u1ee9a m\u1ed9t map v\xe0 ta mu\u1ed1n thay \u0111\u1ed5i map trong method c\u1ee7a struct \u1ea5y. Xem [v\xed d\u1ee5 sau](https://github.com/ducnguyen96/ducnguyen96.github.io/tree/master/static/code/blog/go-copying-mutex):\\n\\n```go\\npackage main\\n\\nimport \\"fmt\\"\\n\\ntype Container struct {\\n  counters map[string]int\\n}\\n\\nfunc (c Container) inc(name string) {\\n  c.counters[name]++\\n}\\n\\nfunc main() {\\n  c := Container{counters: map[string]int{\\"a\\": 0, \\"b\\": 0}}\\n\\n  doIncrement := func(name string, n int) {\\n    for i := 0; i < n; i++ {\\n      c.inc(name)\\n    }\\n  }\\n\\n  doIncrement(\\"a\\", 100000)\\n\\n  fmt.Println(c.counters)\\n}\\n```\\n\\nN\u1ebfu ta ch\u1ea1y \u0111o\u1ea1n script n\xe0y th\xec n\xf3 s\u1ebd in ra:\\n\\n```bash\\nmap[a:100000 b:0]\\n```\\n\\nB\xe2y gi\u1edd gi\u1ea3 s\u1eed ta mu\u1ed1n 2 goroutines g\u1ecdi `inc` m\u1ed9t c\xe1ch concurrent. \u0110\u1ec3 ph\xf2ng tr\u01b0\u1eddng h\u1ee3p x\u1ea3y ra race conditions th\xec ta s\u1ebd s\u1eed d\u1ee5ng `Mutex` \u0111\u1ec3 lock:\\n\\n```go\\npackage main\\n\\nimport (\\n  \\"fmt\\"\\n  \\"sync\\"\\n  \\"time\\"\\n)\\n\\ntype Container struct {\\n  sync.Mutex                       // <-- Added a mutex\\n  counters map[string]int\\n}\\n\\nfunc (c Container) inc(name string) {\\n  c.Lock()                         // <-- Added locking of the mutex\\n  defer c.Unlock()\\n  c.counters[name]++\\n}\\n\\nfunc main() {\\n  c := Container{counters: map[string]int{\\"a\\": 0, \\"b\\": 0}}\\n\\n  doIncrement := func(name string, n int) {\\n    for i := 0; i < n; i++ {\\n      c.inc(name)\\n    }\\n  }\\n\\n  go doIncrement(\\"a\\", 100000)\\n  go doIncrement(\\"a\\", 100000)\\n\\n  // Wait a bit for the goroutines to finish\\n  time.Sleep(300 * time.Millisecond)\\n  fmt.Println(c.counters)\\n}\\n```\\n\\nB\u1ea1n ngh\u0129 output s\u1ebd nh\u01b0 th\u1ebf n\xe0o?\\n\\n```bash\\nfatal error: concurrent map writes\\n\\ngoroutine 5 [running]:\\nruntime.throw(0x4b765b, 0x15)\\n\\n<...> more goroutine stacks\\nexit status 2\\n```\\n\\nT\u1ea1i sao ta \u0111\xe3 c\u1ea9n th\u1ea9n s\u1eed d\u1ee5ng `Mutex` r\u1ed3i m\xe0 v\u1eabn l\u1ed7i? Sai \u1edf \u0111\xe2u? G\u1ee3i \xfd: ch\u1ec9 c\u1ea7n thay \u0111\u1ed5i 1 k\xfd t\u1ef1!\\n\\nV\u1ea5n \u0111\u1ec1 \u1edf \u0111\xe2y l\xe0 khi `inc` \u0111\u01b0\u1ee3c g\u1ecdi, th\xec `c` \u0111\u01b0\u1ee3c copy v\xec ta defined `inc` v\u1edbi receiver l\xe0 `Container` ch\u1ee9 k ph\u1ea3i `*Container` n\xean `inc` kh\xf4ng th\u1ec3 thay \u0111\u1ed5i \u0111\u01b0\u1ee3c `c`.\\n\\nNh\u01b0ng khoan, v\u1eady t\u1ea1i sao v\xed d\u1ee5 \u0111\u1ea7u ti\xean l\u1ea1i kh\xf4ng l\u1ed7i? \u1ede V\xed d\u1ee5 \u0111\u1ea7u ta c\u0169ng d\xf9ng `Container` ch\u1ee9 k ph\u1ea3i `*Container`. V\xec map c\xf3 type l\xe0 type tham chi\u1ebfu kh\xf4ng ph\u1ea3i type gi\xe1 tr\u1ecb, counters trong `Containers` kh\xf4ng ch\u1ee9a gi\xe1 tr\u1ecb th\u1ef1c c\u1ee7a map m\xe0 ch\u1ee9a m\u1ed9t pointer. Cho n\xean khi ta t\u1ea1o copy c\u1ee7a `Container` th\xec counters c\u1ee7a n\xf3 v\u1eabn c\xf3 c\xf9ng data.\\n\\nV\u1eady th\xec v\xed d\u1ee5 ban \u0111\u1ea7u m\u1eb7c d\xf9 kh\xf4ng l\u1ed7i nh\u01b0ng n\xf3 sai, n\xf3 kh\xf4ng tu\xe2n theo [guidelines](https://golang.org/doc/faq#methods_on_values_or_pointers); c\xe1c methods m\xe0 thay \u0111\u1ed5i object th\xec n\xean \u0111\u01b0\u1ee3c defined v\u1edbi pointers, kh\xf4ng ph\u1ea3i values. S\u1eed d\u1ee5ng map \u1edf \u0111\xe2y d\u1eabn t\u1edbi v\u1ea5n \u0111\u1ec1 b\u1ea3o m\u1eadt.\\n\\n`Mutex` c\xf3 type gi\xe1 tr\u1ecb (xem \u0111\u1ecbnh ngh\u0129a \u1edf [Go\'s source](https://golang.org/src/sync/mutex.go), bao g\u1ed3m c\u1ea3 ph\u1ea7n b\xecnh lu\u1eadn khuy\xean r\u1eb1ng kh\xf4ng n\xean copy mutexes), cho n\xean copy l\xe0 kh\xf4ng \u0111\xfang.\\n\\n```go\\nfunc (c *Container) inc(name string) {\\n  c.Lock()\\n  defer c.Unlock()\\n  c.counters[name]++\\n}\\n```\\n\\n\u1ede \u0111\xe2y th\xec `c` l\xe0 m\u1ed9t pointer v\xe0 th\u1ef1c s\u1ef1 tham chi\u1ebfu \u0111\u1ebfn c\xf9ng instance `Container` trong b\u1ed9 nh\u1edb.\\n\\n\u0110\xe2y l\xe0 m\u1ed9t l\u1ed7i kh\xe1 th\u01b0\u1eddng g\u1eb7p, nh\u1ea5t l\xe0 \u1edf nh\u1eefng ch\u1ed7 nh\u01b0 HTTP handlers, ch\xfang th\u01b0\u1eddng \u0111\u01b0\u1ee3c g\u1ecdi concurrently m\xe0 kh\xf4ng c\u1ea7n d\xf9ng `go` statement. Ta s\u1ebd n\xf3i v\u1ec1 v\u1ea5n \u0111\u1ec1 n\xe0y \u1edf m\u1ed9t b\xe0i vi\u1ebft kh\xe1c.\\n\\nL\u1ed7i n\xe0y th\u1ef1c s\u1ef1 gi\xfap ch\xfang ta th\u1ea5y r\xf5 s\u1ef1 kh\xe1c bi\u1ec7t gi\u1eefa value receivers v\xe0 pointer receivers trong Go. \u0110\xe2y l\xe0 m\u1ed9t v\xed d\u1ee5 kh\xe1c kh\xf4ng li\xean quan \u0111\u1ebfn 2 v\xed d\u1ee5 tr\xean, n\xf3 s\u1eed d\u1ee5ng kh\u1ea3 n\u0103ng t\u1ea1o pointer c\u1ee7a Go v\u1edbi `&` v\xe0 `%p`.\\n\\n```go\\npackage main\\n\\nimport \\"fmt\\"\\n\\ntype Container struct {\\n  i int\\n  s string\\n}\\n\\nfunc (c Container) byValMethod() {\\n  fmt.Printf(\\"byValMethod got &c=%p, &(c.s)=%p\\\\n\\", &c, &(c.s))\\n}\\n\\nfunc (c *Container) byPtrMethod() {\\n  fmt.Printf(\\"byPtrMethod got &c=%p, &(c.s)=%p\\\\n\\", c, &(c.s))\\n}\\n\\nfunc main() {\\n  var c Container\\n  fmt.Printf(\\"in main &c=%p, &(c.s)=%p\\\\n\\", &c, &(c.s))\\n\\n  c.byValMethod()\\n  c.byPtrMethod()\\n}\\n```\\n\\nCho ra output nh\u01b0 sau:\\n\\n```bash\\nin main &c=0xc00000a060, &(c.s)=0xc00000a068\\nbyValMethod got &c=0xc00000a080, &(c.s)=0xc00000a088\\nbyPtrMethod got &c=0xc00000a060, &(c.s)=0xc00000a068\\n```\\n\\nH\xe0m main t\u1ea1o m\u1ed9t `Container` v\xe0 in ra address c\u1ee7a n\xf3 c\u0169ng nh\u01b0 address c\u1ee7a field `s`. Sau \u0111\xf3 n\xf3 g\u1ecdi 2 methods c\u1ee7a `Container`.\\n\\n`byValMethod` c\xf3 value receiver, n\xf3 in ra address kh\xe1c v\xec receiver c\u1ee7a n\xf3 l\xe0 1 b\u1ea3n copy c\u1ee7a `Container`. M\u1eb7c kh\xe1c, `byPtrMethod` c\xf3 pointer receiver v\xe0 in ra c\xf9ng address v\u1edbi c\xe1i \u0111\u01b0\u1ee3c in ra b\u1edfi h\xe0m main v\xec receiver l\xe0 address c\u1ee7a `Container` kh\xf4ng ph\u1ea3i l\xe0 copy.\\n\\n## Ngu\u1ed3n\\n\\n- https://eli.thegreenplace.net/2018/beware-of-copying-mutexes-in-go/"},{"id":"/2017/benefits-of-dependencies-in-software-projects-as-a-function-of-effort","metadata":{"permalink":"/en/blog/2017/benefits-of-dependencies-in-software-projects-as-a-function-of-effort","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2017/benefits-of-dependencies-in-software-projects-as-a-function-of-effort.md","source":"@site/blog/2017/benefits-of-dependencies-in-software-projects-as-a-function-of-effort.md","title":"H\xe0m s\u1ed1 bi\u1ec3u th\u1ecb m\u1ed1i t\u01b0\u01a1ng quan gi\u1eefa effort b\u1ecf ra v\xe0 l\u1ee3i \xedch khi s\u1eed d\u1ee5ng dependencies trong c\xe1c d\u1ef1 \xe1n ph\u1ea7n m\u1ec1m.","description":"H\xe0m s\u1ed1 bi\u1ec3u th\u1ecb m\u1ed1i t\u01b0\u01a1ng quan gi\u1eefa effort b\u1ecf ra v\xe0 l\u1ee3i \xedch khi s\u1eed d\u1ee5ng dependencies trong c\xe1c d\u1ef1 \xe1n ph\u1ea7n m\u1ec1m.","date":"2023-12-15T05:08:15.000Z","formattedDate":"December 15, 2023","tags":[{"label":"Programming","permalink":"/en/blog/tags/programming"}],"readingTime":4.78,"hasTruncateMarker":false,"authors":[{"name":"Eli Bendersky","title":"Developer","url":"https://eli.thegreenplace.net","imageURL":"https://avatars.githubusercontent.com/u/1130906?v=4","key":"eliben"},{"name":"\u0110\u1ee9c Nguy\u1ec5n","title":"Developer, Translator","url":"https://github.com/ducnguyen96","imageURL":"https://avatars.githubusercontent.com/u/47471616?v=4","key":"ducnguyen96"}],"frontMatter":{"title":"H\xe0m s\u1ed1 bi\u1ec3u th\u1ecb m\u1ed1i t\u01b0\u01a1ng quan gi\u1eefa effort b\u1ecf ra v\xe0 l\u1ee3i \xedch khi s\u1eed d\u1ee5ng dependencies trong c\xe1c d\u1ef1 \xe1n ph\u1ea7n m\u1ec1m.","description":"H\xe0m s\u1ed1 bi\u1ec3u th\u1ecb m\u1ed1i t\u01b0\u01a1ng quan gi\u1eefa effort b\u1ecf ra v\xe0 l\u1ee3i \xedch khi s\u1eed d\u1ee5ng dependencies trong c\xe1c d\u1ef1 \xe1n ph\u1ea7n m\u1ec1m.","authors":["eliben","ducnguyen96"],"tags":["Programming"],"hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"H\xe3y ch\xfa \xfd khi s\u1eed d\u1ee5ng mutexes trong Go.","permalink":"/en/blog/2018/beware-of-copying-mutexes-in-go"},"nextItem":{"title":"V\xf2ng \u0111\u1eddi c\u1ee7a m\u1ed9t HTTP request trong Go server","permalink":"/en/blog/2021/life-of-an-http-request-in-a-go-server"}},"content":"M\u1ed9t trong nh\u1eefng tranh lu\u1eadn ph\u1ed5 bi\u1ebfn nh\u1ea5t trong ng\xe0nh ph\u1ea7n m\u1ec1m l\xe0 dependencies t\u1ed1t hay x\u1ea5u. C\xf3 n\xean t\u1ef1 vi\u1ebft t\u1ea5t c\u1ea3 ho\u1eb7c h\u1ea7u h\u1ebft c\xe1c ch\u1ee9c n\u0103ng c\u1ee7a d\u1ef1 \xe1n, hay l\xe0 n\xean s\u1eed d\u1ee5ng c\xe1c th\u01b0 vi\u1ec7n c\xf3 s\u1eb5n \u0111\u1ec3 th\u1ef1c hi\u1ec7n c\xe1c t\xe1c v\u1ee5 con m\xe0 d\u1ef1 \xe1n c\u1ea7n th\u1ef1c hi\u1ec7n.\\n\\nM\u1ed9t m\u1eb7t, dependencies gi\xfap c\xe1c teams nh\u1ecf c\xf3 th\u1ec3 ph\xe1t tri\u1ec3n c\xe1c \u1ee9ng d\u1ee5ng t\u01b0\u01a1ng \u0111\u1ed1i ph\u1ee9c t\u1ea1p. M\u1eb7t kh\xe1c th\xec vi\u1ec7c c\xf3 v\xf4 s\u1ed1 th\u01b0 vi\u1ec7n v\xe0 frameworks c\u0169ng l\xe0 m\u1ed9t v\u1ea5n \u0111\u1ec1 bi\u1ec3u hi\u1ec7n qua nhi\u1ec1u m\u1eb7t kh\xe1c nhau, t\u1eeb [leftpad fiasco](https://en.wikipedia.org/wiki/Leftpad) cho \u0111\u1ebfn c\xe1c frameworks ra \u0111\u1eddi tr\xe0n lan l\xe0n, frameworks m\u1edbi thay frameworks c\u0169, h\u1ee3c ch\u01b0a xong framework n\xe0y th\xec \u0111\xe3 c\xf3 m\u1ed9t framework kh\xe1c.\\n\\nN\u1ebfu b\u1ea1n hay theo d\xf5i tin t\u1ee9c v\u1ec1 l\u1eadp tr\xecnh th\xec m\u1ecdi ng\u01b0\u1eddi tranh lu\u1eadn v\u1ec1 v\u1ea5n \u0111\u1ec1 n\xe0y \u1edf m\u1ecdi n\u01a1i. C\xe1c b\xe0i vi\u1ebft nh\u01b0 [vi\u1ebft web apps (ch\u1ec9 s\u1eed d\u1ee5ng std lib)](https://golang.org/doc/articles/wiki/) g\xe2y n\xean [tranh c\xe3i](https://news.ycombinator.com/item?id=13247858), m\u1ed9t m\u1eb7t th\xec \u1ee7ng h\u1ed9 \\"no-dependencies\\", ca ng\u1ee3i t\xednh r\xf5 r\xe0ng, \xedt ph\u1ee5 thu\u1ed9c, d\u1ec5 d\xe0ng maintain v\xe0 deploy. M\u1eb7t kh\xe1c th\xec c\u0169ng c\xf3 nhi\u1ec1u ng\u01b0\u1eddi cho r\u1eb1ng vi\u1ec7c \\"reinvent the wheel\\" l\xe0m ph\xed ph\u1ea1m nh\u1eefng \u0111i\u1ec1u \u0111\xe3 kh\xf3 kh\u0103n \u0111\u1ec3 \u0111\u1ea1t \u0111\u01b0\u1ee3c nh\u1edd nh\u1eefng ng\u01b0\u1eddi th\u01b0 vi\u1ec7n kia.\\n\\nB\xe0i vi\u1ebft n\xe0y mu\u1ed1n \u0111\u1ec1 ra m\u1ed9t c\xf4ng th\u1ee9c \u0111\u01a1n gi\u1ea3n \u0111\u1ec3 xoa d\u1ecbu b\u1edbt nh\u1eefng cu\u1ed9c tranh lu\u1eadn t\u01b0\u01a1ng t\u1ef1, v\xec theo \xfd ki\u1ebfn c\xe1 nh\xe2n th\xec c\u1ea3 2 b\xean \u0111\u1ec1u \u0111\xfang - d\u1ef1a v\xe0o t\u1eebng t\xecnh hu\u1ed1ng c\u1ee5 th\u1ec3.\\n\\n> L\u1ee3i \xedch c\u1ee7a vi\u1ec7c s\u1eed d\u1ee5ng dependencies th\xec t\u1ef7 l\u1ec7 ngh\u1ecbch v\u1edbi l\u01b0\u1ee3ng c\xf4ng s\u1ee9c b\u1ecf ra cho d\u1ef1 \xe1n.\\n\\n<div align=\\"center\\">\\n ![benefits-vs-effort.png](./img/benefits-vs-effort.png)\\n</div>\\n\\nC\xe0ng nhi\u1ec1u n\u1ed7 l\u1ef1c ph\u1ea3i b\u1ecf ra cho m\u1ed9t d\u1ef1 \xe1n th\xec c\xe0ng \xedt l\u1ee3i \xedch nh\u1eadn \u0111\u01b0\u1ee3c khi s\u1eed d\u1ee5ng dependencies. Nh\u1eefng d\u1ef1 \xe1n c\u1ea7n \xedt effort h\xec c\xe0ng s\u1ebd h\u01b0\u1edfng l\u1ee3i t\u1eeb dependencies. V\u1edbi c\xe1c d\u1ef1 \xe1n l\u1edbn, l\xe2u d\xe0i th\xec l\u1ee3i \xedch l\xe0 kh\xf4ng nhi\u1ec1u, th\u1eadm ch\xed th\xec h\u1ea1i c\xf2n nhi\u1ec1u h\u01a1n l\u1ee3i.\\n\\nC\xf4ng th\u1ee9c n\xe0y d\u1ef1a tr\xean s\u1ef1 quan s\xe1t trong su\u1ed1t m\u1ed9t s\u1ef1 nghi\u1ec7p d\xe0i ph\xe1t tri\u1ec3n ph\u1ea7n m\u1ec1m, qu\u1ea3n l\xfd c\xe1c nh\xe0 ph\xe1t tri\u1ec3n ph\u1ea7n m\u1ec1m, v\xe0 quan s\xe1t k\u1ef9 c\xe0ng th\u1ebf gi\u1edbi c\u1ee7a ph\xe1t tri\u1ec3n ph\u1ea7n m\u1ec1m.\\n\\nCh\u1eb3ng h\u1ea1n v\u1edbi ph\xe1t tri\u1ec3n web. N\u1ebfu b\u1ea1n l\xe0 m\u1ed9t nh\xe0 th\u1ea7u th\u01b0\u1eddng xuy\xean ph\xe1t tri\u1ec3n web apps cho kh\xe1ch h\xe0ng m\u1ed7i 2-3 tu\u1ea7n, th\xec ch\u1eafc ch\u1eafn d\u1ef1 \xe1n c\u1ee7a b\u1ea1n s\u1ebd s\u1eed d\u1ee5ng c\xe1c th\u01b0 vi\u1ec7n v\xe0 frameworks. N\xf3 ti\u1ebft ki\u1ec7m r\u1ea5t nhi\u1ec1u th\u1eddi gian v\xe0 c\xf4ng s\u1ee9c, v\u1eady t\u1ea1i sao kh\xf4ng?\\n\\nTuy nhi\xean, n\u1ebfu c\xf4ng ty b\u1ea1n c\xf3 m\u1ed9t web app l\u1edbn v\xe0 ph\u1ee9c t\u1ea1p m\xe0 4 k\u1ef9 s\u01b0 \u0111\xe3 ph\xe1t tri\u1ec3n trong v\xe0i n\u0103m qua (v\xe0 s\u1ebd ti\u1ebfp t\u1ee5c ph\xe1t tri\u1ec3n trong t\u01b0\u01a1ng lai), th\xec kh\u1ea3 n\u0103ng l\xe0 b\u1ea1n ch\u1ec9 s\u1eed d\u1ee5ng c\xe1c th\u01b0 vi\u1ec7n c\u01a1 b\u1ea3n nh\u1ea5t (v\xed d\u1ee5 nh\u01b0 jQuery), v\xe0 ph\u1ea7n c\xf2n l\u1ea1i \u0111\u01b0\u1ee3c ph\xe1t tri\u1ec3n trong c\xf4ng ty.\\n\\nS\u1ef1 kh\xe1c bi\u1ec7t gi\u1eefa c\xe1c th\u01b0 vi\u1ec7n c\u01a1 b\u1ea3n v\xe0 c\xe1c th\u01b0 vi\u1ec7n kh\xe1c c\xf2n l\xe0 v\u1ea5n \u0111\u1ec1 v\u1ec1 quy m\xf4. Kh\xf4ng nhi\u1ec1u c\xf4ng ty s\u1ebd t\u1ef1 vi\u1ebft m\u1ed9t database cho d\u1ef1 \xe1n c\u1ee7a h\u1ecd, nh\u01b0ng n\u1ebfu b\u1ea1n ph\xe1t tri\u1ec3n m\u1ed9t d\u1ef1 \xe1n v\u1edbi quy m\xf4 c\u1ee7a Google th\xec vi\u1ec7c t\u1ef1 vi\u1ebft m\u1ed9t [database](https://en.wikipedia.org/wiki/Bigtable) l\xe0 c\xf3 th\u1ec3 hi\u1ec3u \u0111\u01b0\u1ee3c.\\n\\n<div align=\\"center\\">\\n ![reinventing-the-wheel.jpg](./img/reinventing-the-wheel.jpg)\\n</div>\\n\\n\u0110i\u1ec1u th\xfa v\u1ecb l\xe0 m\u1ed9t d\u1ef1 \xe1n c\xf3 th\u1ec3 \u0111i qua c\xe1c \u0111i\u1ec3m kh\xe1c nhau tr\xean \u0111\u01b0\u1eddng cong l\u1ee3i \xedch vs effort trong su\u1ed1t qu\xe1 tr\xecnh ph\xe1t tri\u1ec3n. Nhi\u1ec1u d\u1ef1 \xe1n b\u1eaft \u0111\u1ea7u nh\u1ecf v\xe0 \u0111\u01a1n gi\u1ea3n, ph\u1ee5 thu\u1ed9c v\xe0o c\xe1c dependencies. Tuy nhi\xean, khi th\u1eddi gian tr\xf4i qua v\xe0 nhi\u1ec1u effort \u0111\u01b0\u1ee3c b\u1ecf v\xe0o d\u1ef1 \xe1n, th\xec kh\xf4ng th\u1ec3 tr\xe1nh kh\u1ecfi vi\u1ec7c dependencies b\u1ecb thay th\u1ebf b\u1eb1ng c\xe1c th\u01b0 vi\u1ec7n trong c\xf4ng ty. \u0110i\u1ec1u n\xe0y th\u01b0\u1eddng x\u1ea3y ra khi c\xe1c dependencies kh\xf4ng c\xf2n \u0111\xe1p \u1ee9ng \u0111\u01b0\u1ee3c t\u1ea5t c\u1ea3 c\xe1c use case m\xe0 d\u1ef1 \xe1n c\u1ea7n. Nh\u1eefng l\xfd do kh\xe1c bao g\u1ed3m t\u1ed1c \u0111\u1ed9 ph\xe1t tri\u1ec3n nhanh h\u01a1n; \u0111\u1ec3 c\u1eadp nh\u1eadt m\u1ed9t dependency, c\u1ea7n ph\u1ea3i push changes \u0111\u1ebfn lib/frameworks v\xe0, ch\u1edd \u0111\u01b0\u1ee3c aprroved v\xe0 merged. Kh\xf4ng ph\u1ea3i team n\xe0o c\u0169ng th\xedch ch\u1edd \u0111\u1ee3i.\\n\\nM\u1ed9t v\xed d\u1ee5 \u0111i\u1ec3n h\xecnh l\xe0 c\xe1c nh\xe0 ph\xe1t tri\u1ec3n game 3D. H\u1ea7u h\u1ebft c\xe1c studio nh\u1ecf v\xe0 c\xe1c nh\xe0 ph\xe1t tri\u1ec3n \u0111\u1ec1u b\u1eaft \u0111\u1ea7u b\u1eb1ng vi\u1ec7c s\u1eed d\u1ee5ng m\u1ed9t trong c\xe1c game engine c\xf3 s\u1eb5n v\xe0 t\u1eadp trung v\xe0o n\u1ed9i dung c\u1ee7a game. Tuy nhi\xean, sau m\u1ed9t th\u1eddi gian, nhi\u1ec1u studio l\u1edbn h\u01a1n l\u1ea1i ph\xe1t tri\u1ec3n c\xe1c engine ri\xeang \u0111\u1ec3 ph\u1ee5c v\u1ee5 nhu c\u1ea7u c\u1ee7a ri\xeang h\u1ecd. C\xf4ng s\u1ee9c b\u1ecf ra cho d\u1ef1 \xe1n l\u1edbn h\u01a1n, v\xec v\u1eady dependencies kh\xf4ng c\xf2n c\xf3 l\u1ee3i n\u1eefa.\\n\\nM\u1ed9t trong nh\u1eefng b\xe0i vi\u1ebft trong nh\u1ea5t v\u1ec1 ch\u1ee7 \u0111\u1ec1 n\xe0y l\xe0 c\u1ee7a Joel Spolsky\'s - [In Defense of Not-Invented-Here Syndrome (from 2001)](https://www.joelonsoftware.com/2001/10/14/in-defense-of-not-invented-here-syndrome/). Trong b\xe0i n\xe0y th\xec Joel \u0111\xe3 ch\u1ec9 ra c\xe1ch m\xe0 Microsoft Excel team \u0111\xe3 ph\u1ea3i \u0111\u1ea5u tranh \u0111\u1ec3 b\u1ecf t\u1ea5t c\u1ea3 c\xe1c dependencies ra kh\u1ecfi d\u1ef1 \xe1n c\u1ee7a h\u1ecd, v\xe0 t\u1ef1 vi\u1ebft ri\xeang m\u1ed9t C compiler. H\u1ecd kh\xf4ng l\xe0m th\u1ebf v\xec ngu ng\u1ed1c hay ki\xeau ng\u1ea1o m\xe0 \u0111\u01a1n gi\u1ea3n v\xec n\xf3 ph\xf9 h\u1ee3p cho d\u1ef1 \xe1n kh\u1ed5ng l\u1ed3 c\u1ee7a h\u1ecd.\\n\\nQuan \u0111i\u1ec3m c\u1ee7a Joel h\u01a1i kh\xe1c so v\u1edbi c\u1ee7a t\u1ed9i - anh \u1ea5y cho r\u1eb1ng c\xe1c t\xednh n\u0103ng c\u1ed1t l\xf5i n\xean t\u1ef1 ph\xe1t tri\u1ec3n. \u0110i\u1ec1u n\xe0y l\xe0 \u0111\xfang tuy nhi\xean c\xf4ng th\u1ee9c n\xeau tr\xean mu\u1ed1n nh\xecn theo m\u1ed9t g\xf3c \u0111\u1ed9 kh\xe1c. Khi m\u1edbi b\u1eaft \u0111\u1ea7u th\xec framework m\xe0 b\u1ea1n s\u1eed d\u1ee5ng kh\xf4ng ph\u1ea3i l\xe0 t\xednh n\u0103ng c\u1ed1t l\xf5i - ch\u1ec9 l\xe0 m\u1ed9t c\xf4ng c\u1ee5. Tuy nhi\xean theo th\u1eddi gian th\xec c\xf3 th\u1ec3 xem n\xf3 nh\u01b0 l\xe0 m\u1ed9t t\xednh n\u0103ng c\u1ed1t l\xf5i, v\xec \u0111\xe3 c\xf3 r\u1ea5t nhi\u1ec1u effort \u0111\xe3 \u0111\u01b0\u1ee3c d\xe0nh cho d\u1ef1 \xe1n; c\xe1i gi\xe1 \u0111\u1ec3 lo\u1ea1i b\u1ecf n\xf3 \u0111\u01b0\u1ee3c gi\u1ea3m b\u1edbt.\\n\\n## Ngu\u1ed3n\\n\\n- https://eli.thegreenplace.net/2017/benefits-of-dependencies-in-software-projects-as-a-function-of-effort/"},{"id":"/2021/life-of-an-http-request-in-a-go-server","metadata":{"permalink":"/en/blog/2021/life-of-an-http-request-in-a-go-server","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2021/life-of-an-http-request-in-a-go-server.md","source":"@site/blog/2021/life-of-an-http-request-in-a-go-server.md","title":"V\xf2ng \u0111\u1eddi c\u1ee7a m\u1ed9t HTTP request trong Go server","description":"V\xf2ng \u0111\u1eddi c\u1ee7a m\u1ed9t HTTP request trong Go server.","date":"2023-12-15T05:08:15.000Z","formattedDate":"December 15, 2023","tags":[{"label":"Go","permalink":"/en/blog/tags/go"},{"label":"Programming","permalink":"/en/blog/tags/programming"}],"readingTime":9.675,"hasTruncateMarker":false,"authors":[{"name":"Eli Bendersky","title":"Developer","url":"https://eli.thegreenplace.net","imageURL":"https://avatars.githubusercontent.com/u/1130906?v=4","key":"eliben"},{"name":"\u0110\u1ee9c Nguy\u1ec5n","title":"Developer, Translator","url":"https://github.com/ducnguyen96","imageURL":"https://avatars.githubusercontent.com/u/47471616?v=4","key":"ducnguyen96"}],"frontMatter":{"title":"V\xf2ng \u0111\u1eddi c\u1ee7a m\u1ed9t HTTP request trong Go server","description":"V\xf2ng \u0111\u1eddi c\u1ee7a m\u1ed9t HTTP request trong Go server.","authors":["eliben","ducnguyen96"],"tags":["Go","Programming"],"hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"H\xe0m s\u1ed1 bi\u1ec3u th\u1ecb m\u1ed1i t\u01b0\u01a1ng quan gi\u1eefa effort b\u1ecf ra v\xe0 l\u1ee3i \xedch khi s\u1eed d\u1ee5ng dependencies trong c\xe1c d\u1ef1 \xe1n ph\u1ea7n m\u1ec1m.","permalink":"/en/blog/2017/benefits-of-dependencies-in-software-projects-as-a-function-of-effort"},"nextItem":{"title":"Different approaches to HTTP routing in Go","permalink":"/en/blog/2023/go-routing"}},"content":"Go l\xe0 m\u1ed9t ng\xf4n ng\u1eef ph\u1ed5 bi\u1ebfn v\xe0 r\u1ea5t ph\xf9 h\u1ee3p \u0111\u1ec3 vi\u1ebft HTTP servers. B\xe0i vi\u1ebft n\xe0y th\u1ea3o lu\u1eadn v\u1ec1 v\xf2ng \u0111\u1eddi c\u1ee7a m\u1ed9t HTTP request v\xe0 s\u1ebd \u0111\u1ec1 c\u1eadp \u0111\u1ebfn m\u1ed9t s\u1ed1 ch\u1ee7 \u0111\u1ec1 nh\u01b0 routers, middleware v\xe0 m\u1ed9t s\u1ed1 th\u1ee9 li\xean quan kh\xe1c ch\u1eb3ng h\u1ea1n nh\u01b0 concurrency.\\n\\nCode c\u1ee5 th\u1ec3 \u0111\u1ec5 theo d\xf5i b\xe0i vi\u1ebft c\xf3 th\u1ec3 xem [t\u1ea1i \u0111\xe2y](https://gobyexample.com/http-servers)\\n\\n```go\\npackage main\\n\\nimport (\\n  \\"fmt\\"\\n  \\"net/http\\"\\n)\\n\\nfunc hello(w http.ResponseWriter, req *http.Request) {\\n  fmt.Fprintf(w, \\"hello\\\\n\\")\\n}\\n\\nfunc headers(w http.ResponseWriter, req *http.Request) {\\n  for name, headers := range req.Header {\\n    for _, h := range headers {\\n      fmt.Fprintf(w, \\"%v: %v\\\\n\\", name, h)\\n    }\\n  }\\n}\\n\\nfunc main() {\\n  http.HandleFunc(\\"/hello\\", hello)\\n  http.HandleFunc(\\"/headers\\", headers)\\n\\n  http.ListenAndServe(\\":8090\\", nil)\\n}\\n```\\n\\nTa b\u1eaft \u0111\u1ea7u truy v\u1ebft v\xf2ng \u0111\u1eddi c\u1ee7a HTTP request b\u1eb1ng c\xe1ch ki\u1ec3m tra h\xe0m `http.ListenAndServe`:\\n\\n```go\\nfunc ListenAndServe(addr string, handler Handler) error\\n```\\n\\nD\u01b0\u1edbi \u0111\xe2y l\xe0 m\u1ed9t s\u01a1 \u0111\u1ed3 \u0111\u01a1n gi\u1ea3n v\u1ec1 c\xe1i g\xec s\u1ebd x\u1ea3y ra khi h\xe0m tr\xean \u0111\u01b0\u1ee3c g\u1ecdi\\n\\n<div align=\\"center\\" style={{\\"backgroundColor\\": \\"white\\"}}>\\n  ![http-request-listenandserve](./img/http-request-listenandserve.png)\\n</div>\\n\\nPhi\xean b\u1ea3n n\xe0y \u0111\xe3 \u0111\u01b0\u1ee3c c\u1eaft g\u1ecdn \u0111i r\u1ea5t nhi\u1ec1u, nh\u01b0ng [phi\xean b\u1ea3n g\u1ed1c](https://go.googlesource.com/go/+/go1.15.8/src/net/http/server.go) c\u0169ng kh\xf4ng qu\xe1 kh\xf3 \u0111\u1ec3 theo d\xf5i cho l\u1eafm.\\n\\n`ListenAndServe` l\u1eafng nghe tr\xean c\u1ed5ng TCP theo \u0111\u1ecba ch\u1ec9 cho tr\u01b0\u1edbc, sau \u0111\xf3 c\xe1c v\xf2ng l\u1eb7p ch\u1ea5p nh\u1eadn c\xe1c connections. V\u1edbi m\u1ed7i connection th\xec Go s\u1ebd d\xf9ng 1 goroutine \u0111\u1ec3 x\u1eed l\xfd. Vi\u1ec7c x\u1eed l\xfd m\u1ed7i connection th\xec n\u1eb1m trong v\xf2ng l\u1eb7p sau:\\n\\n- Parse HTTP request t\u1eeb connection v\xe0 t\u1ea1o ra `http.Request`\\n- Pass `http.Request` \u0111\u1ebfn 1 handler \u0111\xe3 \u0111\u01b0\u1ee3c user defined\\n\\nHandler l\xe0 b\u1ea5t c\u1ee9 th\u1ee9 g\xec c\xf3 implement `http.Handler` interface:\\n\\n```go\\ntype Handler interface {\\n    ServeHTTP(ResponseWriter, *Request)\\n}\\n```\\n\\n## Default handler\\n\\n\u1ede v\xed d\u1ee5 tr\xean, `ListenAndServe` \u0111\u01b0\u1ee3c g\u1ecdi v\u1edbi tham s\u1ed1 th\u1ee9 2 l\xe0 `nil` trong khi \u0111\xe1ng nh\u1ebd ph\u1ea3i l\xe0 1 handler \u0111\xe3 \u0111\u01b0\u1ee3c user defined.\\n\\nS\u01a1 \u0111\u1ed3 c\u1ee7a ch\xfang ta \u0111\xe3 gi\u1ea3n l\u01b0\u1ee3c \u0111i v\xe0i chi ti\u1ebft, th\u1ef1c t\u1ebft th\xec khi `http` package ph\u1ee5c v\u1ee5 1 request. n\xf3 kh\xf4ng g\u1ecdi tr\u1ef1c ti\u1ebfp t\u1edbi handler c\u1ee7a user m\xe0 s\u1eed d\u1ee5ng adapter n\xe0y:\\n\\n```go\\ntype serverHandler struct {\\n  srv *Server\\n}\\n\\nfunc (sh serverHandler) ServeHTTP(rw ResponseWriter, req *Request) {\\n  handler := sh.srv.Handler\\n  // highlight-start\\n  if handler == nil {\\n    handler = DefaultServeMux\\n  }\\n  // highlight-end\\n  if req.RequestURI == \\"*\\" && req.Method == \\"OPTIONS\\" {\\n    handler = globalOptionsHandler{}\\n  }\\n  handler.ServeHTTP(rw, req)\\n}\\n```\\n\\nCh\xfa \xfd \u0111\u1ebfn nh\u1eefng d\xf2ng \u0111\xe3 \u0111\u01b0\u1ee3c highlighted. N\u1ebfu `handler == nil` th\xec `http.DefaultServeMux` s\u1ebd \u0111\u01b0\u1ee3c s\u1eed d\u1ee5ng nh\u01b0 1 handler. \u0110\xe2y l\xe0 server mux m\u1eb7c \u0111\u1ecbnh - 1 global instance c\u1ee7a `http.ServeMux` n\u1eb1m trong `http` package.\\n\\nCh\xfang ta c\xf3 th\u1ec3 vi\u1ebft l\u1ea1i server nh\u01b0 sau m\xe0 kh\xf4ng s\u1eed d\u1ee5ng mux m\u1eb7c \u0111\u1ecbnh. Ch\u1ec9 h\xe0m `main` thay \u0111\u1ed5i n\xean \u1edf \u0111\xe2y s\u1ebd kh\xf4ng show `hello` v\xe0 `headers` n\u1eefa nh\u01b0ng b\u1ea1n c\xf3 th\u1ec3 xem full code [\u1edf \u0111\xe2y](https://github.com/ducnguyen96/ducnguyen96.github.io/tree/master/static/code/blog/go-life-http-request/basic-server-mux-object.go) [^1].\\n\\n```go\\nfunc main() {\\n  mux := http.NewServeMux()\\n  mux.HandleFunc(\\"/hello\\", hello)\\n  mux.HandleFunc(\\"/headers\\", headers)\\n\\n  http.ListenAndServe(\\":8090\\", mux)\\n}\\n```\\n\\n## `ServeMux` ch\u1ec9 l\xe0 `Handler`\\n\\nKhi \u0111\u1ecdc v\xed d\u1ee5 v\u1ec1 Go server th\xec s\u1ebd d\u1ec5 d\xe0ng \u0111i \u0111\u1ebfn k\u1ebft lu\u1eadn r\u1eb1ng `ListenAndServe` nh\u1eadn \\"mux\\" l\xe0 m\u1ed9t tham s\u1ed1, nh\u01b0ng \u0111i\u1ec1u n\xe0y l\xe0 kh\xf4ng ch\xednh x\xe1c. Nh\u01b0 ch\xfang ta \u0111\xe3 th\u1ea5y \u1edf tr\xean th\xec `ListenAndServe` nh\u1eadn m\u1ed9t gi\xe1 tr\u1ecb c\xf3 implement `http.Handler` interface. Ch\xfang ta c\xf3 th\u1ec3 vi\u1ebft m\u1ed9t server m\xe0 kh\xf4ng s\u1eed d\u1ee5ng b\u1ea5t c\u1ee9 mux n\xe0o:\\n\\n```go\\ntype PoliteServer struct {\\n}\\n\\nfunc (ms *PoliteServer) ServeHTTP(w http.ResponseWriter, req *http.Request) {\\n  fmt.Fprintf(w, \\"Welcome! Thanks for visiting!\\\\n\\")\\n}\\n\\nfunc main() {\\n  ps := &PoliteServer{}\\n  log.Fatal(http.ListenAndServe(\\":8090\\", ps))\\n}\\n```\\n\\nCh\xfang ta ch\u01b0a \u0111\u1ecbnh tuy\u1ebft n\xean t\u1ea5t c\u1ea3 c\xe1c HTTP requests s\u1ebd \u0111\u01b0\u1ee3c \u0111\u01b0a \u0111\u1ebfn `ServeHTTP` method c\u1ee7a `PoliteServer` v\xe0 n\xf3 s\u1ebd ph\u1ea3n h\u1ed3i v\u1edbi c\xf9ng 1 message cho t\u1ea5t c\u1ea3.\\n\\nCh\xfang ta c\u0169ng c\xf3 th\u1ec3 l\xe0m server \u0111\u01a1n gi\u1ea3n h\u01a1n n\u1eefa b\u1eb1ng c\xe1ch s\u1eed d\u1ee5ng `http.HandlerFunc`\\n\\n```go\\nfunc politeGreeting(w http.ResponseWriter, req *http.Request) {\\n  fmt.Fprintf(w, \\"Welcome! Thanks for visiting!\\\\n\\")\\n}\\n\\nfunc main() {\\n  log.Fatal(http.ListenAndServe(\\":8090\\", http.HandlerFunc(politeGreeting)))\\n}\\n```\\n\\n`HandlerFunc` \u1edf \u0111\xe2y l\xe0 m\u1ed9t adapter trong `http` package:\\n\\n```go\\n// The HandlerFunc type is an adapter to allow the use of\\n// ordinary functions as HTTP handlers. If f is a function\\n// with the appropriate signature, HandlerFunc(f) is a\\n// Handler that calls f.\\ntype HandlerFunc func(ResponseWriter, *Request)\\n\\n// ServeHTTP calls f(w, r).\\nfunc (f HandlerFunc) ServeHTTP(w ResponseWriter, r *Request) {\\n  f(w, r)\\n}\\n```\\n\\nN\u1ebfu b\u1ea1n \u0111\u1ec3 \xfd `http.HandleFunc` trong v\xed d\u1ee5 \u0111\u1ea7u ti\xean [^2] th\xec n\xf3 c\u0169ng s\u1eed d\u1ee5ng c\xf9ng adapter.\\n\\nGi\u1ed1ng nh\u01b0 `PoliteServer` th\xec `http.ServeMux` l\xe0 m\u1ed9t type c\xf3 implement `http.Handler` interface. B\u1ea1n c\xf3 th\u1ec3 xem k\u1ef9 h\u01a1n \u1edf [\u0111\xe2y](https://go.googlesource.com/go/+/go1.15.8/src/net/http/server.go):\\n\\n- `ServeMux` ch\u1ee9a 1 slice c\xe1c c\u1eb7p `{pattern, handler}` \u0111\xe3 \u0111\u01b0\u1ee3c s\u1eafp x\u1ebfp(theo \u0111\u1ed9 d\xe0i).\\n- `Handle` ho\u1eb7c `HandleFunc` th\xeam m\u1ed9t handler m\u1edbi v\xe0o slice.\\n- `ServeHTTP`:\\n  - T\xecm handler ph\xf9 h\u1ee3p cho request d\u1ef1a v\xe0o path (b\u1eb1ng c\xe1ch t\xecm ki\u1ebfm tr\xean c\xe1c c\u1eb7p \u0111\u01b0\u1ee3c s\u1eafp x\u1ebfp \u1edf tr\xean)\\n  - G\u1ecdi t\u1edbi `ServeHTTP` method c\u1ee7a handler.\\n\\nNh\u01b0 v\u1eady, c\xf3 th\u1ec3 xem mux nh\u01b0 l\xe0 m\u1ed9t _forwarding handler_; pattern n\xe0y r\u1ea5t hay g\u1eb7p \u1edf trong HTTP server - _middleware_\\n\\n## `http.Handler` Middleware\\n\\nR\u1ea5t kh\xf3 \u0111\u1ec3 \u0111\u1ecbnh ngh\u0129a Middleware m\u1ed9t c\xe1ch ch\xednh x\xe1c v\xec n\xf3 mang \xfd ngh\u0129a kh\xe1c nhau d\u1ef1a v\xe0o contexts, languages v\xe0 frameworks.\\n\\n\u0110\u01a1n gi\u1ea3n h\xf3a s\u01a1 \u0111\u1ed3 ban \u0111\u1ea7u m\xe0 ta c\xf3, d\u1ea5u \u0111i m\u1ed9t v\xe0i chi ti\u1ebft trong `http` package ta c\xf3:\\n\\n<div align=\\"center\\" style={{\\"backgroundColor\\": \\"white\\"}}>\\n  ![http-request-simplified.png](./img/http-request-simplified.png)\\n</div>\\n\\nB\xe2y gi\u1edd th\xec sau khi th\xeam middleware n\xf3 s\u1ebd tr\u1edf th\xe0nh:\\n\\n<div align=\\"center\\" style={{\\"backgroundColor\\": \\"white\\"}}>\\n  ![http-request-with-middleware.png](./img/http-request-with-middleware.png)\\n</div>\\n\\nTrong Go th\xec middleware ch\u1ec9 l\xe0 m\u1ed9t HTTP handler b\u1ecdc m\u1ed9t handler kh\xe1c.\\n\\n\u1ede tr\xean th\xec ta \u0111\xe3 th\u1ea5y m\u1ed9t v\xed d\u1ee5 v\u1ec1 middleware - `http.ServeMux`; tr\u01b0\u1eddng h\u1ee3p n\xe0y th\xec middleware s\u1eed d\u1ee5ng \u0111\u1ec3 select handler ph\xf9 h\u1ee3p d\u1ef1a v\xe0o path c\u1ee7a request.\\n\\nM\u1ed9t v\xed d\u1ee5 c\u1ee5 th\u1ec3 kh\xe1c. Quay l\u1ea1i v\xed d\u1ee5 v\u1edbi polite server v\xe0 th\xeam _logging middleware_.\\n\\n```go\\ntype LoggingMiddleware struct {\\n  handler http.Handler\\n}\\n\\nfunc (lm *LoggingMiddleware) ServeHTTP(w http.ResponseWriter, req *http.Request) {\\n  start := time.Now()\\n  lm.handler.ServeHTTP(w, req)\\n  log.Printf(\\"%s %s %s\\", req.Method, req.RequestURI, time.Since(start))\\n}\\n\\ntype PoliteServer struct {\\n}\\n\\nfunc (ms *PoliteServer) ServeHTTP(w http.ResponseWriter, req *http.Request) {\\n  fmt.Fprintf(w, \\"Welcome! Thanks for visiting!\\\\n\\")\\n}\\n\\nfunc main() {\\n  ps := &PoliteServer{}\\n  lm := &LoggingMiddleware{handler: ps}\\n  log.Fatal(http.ListenAndServe(\\":8090\\", lm))\\n}\\n```\\n\\nch\xfa \xfd r\u1eb1ng `LoggingMiddleware` th\u1ef1c ch\u1ea5t l\xe0 m\u1ed9t `http.Handler` c\xf3 m\u1ed9t field l\xe0 user handler. Khi `ListenAndServe` g\u1ecdi `ServeHTTP` method c\u1ea3u n\xf3:\\n\\n1. Ti\u1ec1n x\u1eed l\xfd: t\u1ea1o 1 time stamp tr\u01b0\u1edbc khi user handler ch\u1ea1y.\\n2. G\u1ecdi t\u1edbi user handler v\u1edbi request v\xe0 response writer.\\n3. H\u1eadu x\u1eed l\xfd: log request details c\xf9ng v\u1edbi th\u1eddi gian \u0111\xe3 d\xe0nh \u0111\u1ec3 x\u1eed l\xfd request.\\n\\n\u0110i\u1ec1u tuy\u1ec7t v\u1eddi v\u1ec1 middleware l\xe0 n\xf3 composable. Ch\xfang c\xf3 th\u1ec3 n\u1ed1i v\u1edbi nhau t\u1ea1o th\xe0nh m\u1ed9t chu\u1ed7i `http.Handler` bao l\u1ea5y nhau. Th\u1ef1c t\u1ebf th\xec \u0111\xe2y l\xe0 m\u1ed9t pattern th\u01b0\u1eddng th\u1ea5y\\n\\n```go\\nfunc politeGreeting(w http.ResponseWriter, req *http.Request) {\\n  fmt.Fprintf(w, \\"Welcome! Thanks for visiting!\\\\n\\")\\n}\\n\\nfunc loggingMiddleware(next http.Handler) http.Handler {\\n  return http.HandlerFunc(func(w http.ResponseWriter, req *http.Request) {\\n    start := time.Now()\\n    next.ServeHTTP(w, req)\\n    log.Printf(\\"%s %s %s\\", req.Method, req.RequestURI, time.Since(start))\\n  })\\n}\\n\\nfunc main() {\\n  lm := loggingMiddleware(http.HandlerFunc(politeGreeting))\\n  log.Fatal(http.ListenAndServe(\\":8090\\", lm))\\n}\\n```\\n\\nThay v\xec t\u1ea1o m\u1ed9t struct c\xf9ng v\u1edbi methods th\xec `loggingMiddleware` s\u1eed d\u1ee5ng `http.HandlerFunc` v\u1edbi m\u1ed9t closure gi\xfap code ng\u1eafn g\u1ecdn h\u01a1n trong khi v\u1eabn gi\u1eef \u0111\u01b0\u1ee3c \u0111\u1ea7y \u0111\u1ee7 t\xednh n\u0103ng. Quan tr\u1ecdng h\u01a1n th\xec pattern n\xe0y \u0111\xe3 \u0111\u01b0\u1ee3c chu\u1ea9n h\xf3a: m\u1ed9t function nh\u1eadn m\u1ed9t `http.Handler` v\xe0 tr\u1ea3 v\u1ec1 m\u1ed9t `http.Handler` kh\xe1c. Handler \u0111\u01b0\u1ee3c tr\u1ea3 v\u1ec1 s\u1ebd \u0111\u01b0\u1ee3c s\u1eed d\u1ee5ng thay cho handler \u0111\xe3 \u0111\u01b0\u1ee3c truy\u1ec1n v\xe0o middleware v\xe0 n\xf3 s\u1ebd th\u1ef1c hi\u1ec7n ch\u1ee9c n\u0103ng g\u1ed1c c\xf9ng v\u1edbi t\xednh n\u0103ng m\u1edbi c\u1ee7a middleware.\\n\\nV\xed d\u1ee5, th\u01b0 vi\u1ec7n chu\u1ea9n c\xf3 s\u1eb5n m\u1ed9t v\xe0i middleware:\\n\\n```go\\nfunc TimeoutHandler(h Handler, dt time.Duration, msg string) Handler\\n```\\n\\nTa c\xf3 th\u1ec3 s\u1eed d\u1ee5ng n\xf3 nh\u01b0 sau:\\n\\n```go\\nhandler = http.TimeoutHandler(handler, 2 * time.Second, \\"timed out\\")\\n```\\n\\n\u0110o\u1ea1n code tr\xean t\u1ea1o m\u1ed9t version handler m\u1edbi c\xf9ng v\u1edbi c\u01a1 ch\u1ebf timeout trong v\xf2ng 2 gi\xe2y.\\n\\nT\xednh k\u1ebft h\u1ee3p c\u1ee7a middleware c\xf3 th\u1ec3 th\u1ea5y qua v\xed d\u1ee5 sau:\\n\\n```go\\nhandler = http.TimeoutHandler(handler, 2 * time.Second, \\"timed out\\")\\nhandler = loggingMiddleware(handler)\\n```\\n\\nSau 2 d\xf2ng tr\xean th\xec `handler` b\xe2y gi\u1edd c\xf3 th\xeam t\xednh n\u0103ng timeout v\xe0 logging. N\u1ebfu ch\xfa \xfd th\xec c\xf3 th\u1ec3 th\u1ea5y vi\u1ec7c n\u1ed1i m\u1ed9t chu\u1ed7i d\xe0i c\xe1c middlewares s\u1ebd tr\u1edf n\xean kh\xe1 phi\u1ec1n ph\u1ee9c v\xe0 \u0111\xe3 c\xf3 m\u1ed9t v\xe0i package ph\u1ed5 bi\u1ebfn \u0111\u1ec3 gi\u1ea3i quy\u1ebft v\u1ea5n \u0111\u1ec1 n\xe0y nh\u01b0ng n\xf3 n\u1eb1m ngo\xe0i scope c\u1ee7a b\xe0i vi\u1ebft.\\n\\nNh\xe2n ti\u1ec7n th\xec ch\xednh `http` package c\u0169ng s\u1eed d\u1ee5ng middleware \u0111\u1ec5 c\xf3 th\u1ec3 x\u1eed l\xfd tr\u01b0\u1eddng h\u1ee3p `nil` handlers.\\n\\n## Concurrency v\xe0 x\u1eed l\xfd panic\\n\\n\u0110\u1ec3 k\u1ebft th\xfac b\xe0i vi\u1ebft th\xec ta s\u1ebd n\xf3i th\xeam v\u1ec1 2 ch\u1ee7 \u0111\u1ec1: concurrency v\xe0 x\u1eed l\xfd panic\\n\\n\u0110\u1ea7u ti\xean v\u1ec1 _concurrency_. Nh\u01b0 \u0111\xe3 \u0111\u1ec1 c\u1eadp \u1edf tr\xean th\xec m\u1ed7i connection \u0111\u01b0\u1ee3c x\u1eed l\xfd b\u1eb1ng 1 goroutine.\\n\\n\u0110\xe2y l\xe0 m\u1ed9t t\xednh n\u0103ng m\u1ea1nh m\u1ebd c\u1ee7a `net/http`, n\xf3 \u0111\xe3 t\u1eadn d\u1ee5ng kh\u1ea3 n\u0103ng concurrency c\u1ee7a Go, b\u1eb1ng c\xe1ch s\u1eed d\u1ee5ng goroutines th\xec n\xf3 cung c\u1ea5p m\u1ed9t model cho HTTP handler r\u1ea5t clean. M\u1ed9t handler c\xf3 th\u1ec3 block (ch\u1eb3ng h\u1ea1n vi\u1ec7c \u0111\u1ecdc d\u1eef li\u1ec7u t\u1eeb database) m\xe0 kh\xf4ng ph\u1ea3i lo v\u1ec1 vi\u1ec7c ho\xe3n l\u1ea1i c\xe1c handlers kh\xe1c m\u1eb7c d\xf9 n\xf3 y\xeau c\u1ea7u ch\xfang ta ph\u1ea3i c\u1ea9n th\xe2n khi vi\u1ebft handler c\xf3 t\u01b0\u01a1ng t\xe1c v\u1edbi shared data. Xem [b\xe0i vi\u1ebft n\xe0y](/blog/2019/on-concurrency-in-go-http-servers) \u0111\u1ec3 bi\u1ebft th\xeam chi ti\u1ebft.\\n\\nCu\u1ed1i c\xf9ng l\xe0 v\u1ec1 x\u1eed l\xfd panic. M\u1ed9t HTTP server \u0111i\u1ec3n h\xecnh th\xec c\u1ea7n ph\u1ea3i l\xe0 m\u1ed9t process c\xf3 th\u1ec3 ch\u1ea1y li\xean t\u1ee5c. Gi\u1ea3 s\u1eed c\xf3 l\u1ed7i g\xec \u0111\u1ea5y trong handler n\xe0o \u0111\u1ea5y c\u1ee7a user(ch\u1eb3ng h\u1ea1n nh\u01b0 bug d\u1eabn t\u1edbi runtime panic). \u0110i\u1ec1u n\xe0y c\xf3 th\u1ec3 g\xe2y s\u1eadp to\xe0n b\u1ed9 server. \u0110\u1ec3 ph\xf2ng tr\u01b0\u1eddng h\u1ee3p \u0111i\u1ec1u n\xe0y x\u1ea3y ra th\xec b\u1ea1n c\xf3 th\u1ec3 ngh\u0129 t\u1edbi vi\u1ec7c s\u1eed d\u1ee5ng `recover` \u1edf trong `main`, nh\u01b0ng n\xf3 s\u1ebd kh\xf4ng hi\u1ec7u qu\u1ea3 v\xec m\u1ed9t v\xe0i l\xfd do sau \u0111\xe2y:\\n\\n1. T\u1ea1i th\u1eddi \u0111i\u1ec3m ch\u1ea1y t\u1edbi h\xe0m `main` th\xec `ListenAndServe` \u0111\xe3 ch\u1ea1y v\xe0 s\u1ebd kh\xf4ng ti\u1ebfp t\u1ee5c serve n\u1eefa.\\n2. V\xec m\u1ed7i connection \u0111\u01b0\u1ee3c x\u1eed l\xfd b\u1edfi 1 goroutine n\xean khi panics x\u1ea3y ra \u1edf handlers n\xf3 s\u1ebd kh\xf4ng ch\u1ea1y \u0111\u1ebfn h\xe0m `main` m\xe0 s\u1ebd crash.\\n\\n\u0110\u1ec3 gi\u1ea3i quy\u1ebft v\u1ea5n \u0111\u1ec1 n\xe0y th\xec `net/http` c\xf3 recovery \u0111\u01b0\u1ee3c t\xedch h\u1ee3p s\u1eb5n cho t\u1eebng goroutine (n\u1eb1m trong `conn.serve` method). Ch\xfang ta c\xf3 th\u1ec3 th\u1ea5y \u0111\u01b0\u1ee3c qua v\xed d\u1ee5 sau:\\n\\n```go\\nfunc hello(w http.ResponseWriter, req *http.Request) {\\n  fmt.Fprintf(w, \\"hello\\\\n\\")\\n}\\n\\nfunc doPanic(w http.ResponseWriter, req *http.Request) {\\n  panic(\\"oops\\")\\n}\\n\\nfunc main() {\\n  http.HandleFunc(\\"/hello\\", hello)\\n  http.HandleFunc(\\"/panic\\", doPanic)\\n\\n  http.ListenAndServe(\\":8090\\", nil)\\n}\\n```\\n\\nN\u1ebfu ta ch\u1ea1y server v\xe0 d\xf9ng `curl` t\u1edbi `/panic` th\xec \u0111\xe2y l\xe0 output:\\n\\n```bash\\n$ curl localhost:8090/panic\\ncurl: (52) Empty reply from server\\n```\\n\\nV\xe0 server s\u1ebd in ra logs:\\n\\n```bash\\n2021/02/16 09:44:31 http: panic serving 127.0.0.1:52908: oops\\ngoroutine 8 [running]:\\nnet/http.(*conn).serve.func1(0xc00010cbe0)\\n  /usr/local/go/src/net/http/server.go:1801 +0x147\\npanic(0x654840, 0x6f0b80)\\n  /usr/local/go/src/runtime/panic.go:975 +0x47a\\nmain.doPanic(0x6fa060, 0xc0001401c0, 0xc000164200)\\n[... rest of stack dump here ...]\\n```\\n\\nTuy nhi\xean, server v\u1eabn s\u1ebd ti\xe9p t\u1ee5c ch\u1ea1y v\xe0 ta v\u1eabn c\xf3 th\u1ec3 t\u01b0\u01a1ng t\xe1c v\u1edbi n\xf3.\\n\\nM\u1eb7c d\xf9 t\xednh n\u0103ng n\xe0y t\u1ed1t h\u01a1n vi\u1ec7c s\u1eadp server nh\u01b0ng c\xf3 th\u1ec3 th\u1ea5y r\u1eb1ng n\xf3 c\u0169ng c\xf3 m\u1ed9t v\xe0i h\u1ea1n ch\u1ebf. T\u1ea5t c\u1ea3 nh\u1eefng g\xec n\xf3 l\xe0m l\xe0 \u0111\xf3n connection v\xe0 log error; s\u1ebd h\u1eefu \xedch h\u01a1n n\u1ebfu n\xf3 tr\u1ea3 v\u1ec1 cho client error response (ch\u1eb3ng h\u1ea1n nh\u01b0 500 - internal server error).\\n\\nTuy nhi\xean sau khi \u0111\u1ecdc b\xe0i n\xe0y th\xec ch\u1eafc h\u1eb3n b\u1ea1n c\xf3 th\u1ec3 vi\u1ebft 1 middleware cho t\xednh n\u0103ng n\xe0y.\\n\\n## Sources\\n\\n- https://eli.thegreenplace.net/2021/life-of-an-http-request-in-a-go-server/\\n\\n[^1]: C\xf3 m\u1ed9t v\xe0i l\xfd do b\u1ea1n n\xean s\u1eed d\u1ee5ng c\xe1ch n\xe0y thay default mux. S\u1eed d\u1ee5ng default mux kh\xe1 r\u1ee7i ro, v\xec n\xf3 global n\xean n\xf3 c\xf3 th\u1ec3 b\u1ecb thay \u0111\u1ed5i b\u1edfi 1 package n\xe0o \u0111\u1ea5y v\xe0 s\u1eed d\u1ee5ng cho 1 m\u1ee5c \u0111\xedch b\u1ea5t ch\xednh.\\n[^2]: C\u1ea9n th\u1eadn: `http.HandleFunc` v\xe0 `http.HandlerFunc` m\u1eb7c d\xf9 li\xean quan nh\u01b0ng ch\xfang l\xe0 2 \u0111\u1ed1i t\u01b0\u1ee3ng kh\xe1c nhau."},{"id":"/2023/go-routing","metadata":{"permalink":"/en/blog/2023/go-routing","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2023/go-routing.md","source":"@site/blog/2023/go-routing.md","title":"Different approaches to HTTP routing in Go","description":"Sources","date":"2023-12-14T12:48:09.000Z","formattedDate":"December 14, 2023","tags":[{"label":"go","permalink":"/en/blog/tags/go"},{"label":"Networking Programming","permalink":"/en/blog/tags/networking-programming"}],"readingTime":0.02,"hasTruncateMarker":false,"authors":[{"name":"Ben Hoyt","title":"Developer","url":"https://benhoyt.com","imageURL":"https://avatars.githubusercontent.com/u/999033?v=4","key":"benhoyt"},{"name":"\u0110\u1ee9c Nguy\u1ec5n","title":"Developer, Translator","url":"https://github.com/ducnguyen96","imageURL":"https://avatars.githubusercontent.com/u/47471616?v=4","key":"ducnguyen96"}],"frontMatter":{"title":"Different approaches to HTTP routing in Go","authors":["benhoyt","ducnguyen96"],"tags":["go","Networking Programming"],"hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"V\xf2ng \u0111\u1eddi c\u1ee7a m\u1ed9t HTTP request trong Go server","permalink":"/en/blog/2021/life-of-an-http-request-in-a-go-server"},"nextItem":{"title":"What is REST","permalink":"/en/blog/2023/what-is-rest"}},"content":"## Sources\\n\\n- https://benhoyt.com/writings/go-routing/"},{"id":"/2023/what-is-rest","metadata":{"permalink":"/en/blog/2023/what-is-rest","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2023/what-is-rest.md","source":"@site/blog/2023/what-is-rest.md","title":"What is REST","description":"Sources","date":"2023-12-13T13:11:33.000Z","formattedDate":"December 13, 2023","tags":[{"label":"REST","permalink":"/en/blog/tags/rest"},{"label":"API","permalink":"/en/blog/tags/api"},{"label":"HTTP","permalink":"/en/blog/tags/http"},{"label":"Web","permalink":"/en/blog/tags/web"},{"label":"Web Development","permalink":"/en/blog/tags/web-development"},{"label":"Web Services","permalink":"/en/blog/tags/web-services"}],"readingTime":0.02,"hasTruncateMarker":false,"authors":[{"name":"Codeacademy","title":"Company","url":"https://www.codecademy.com","imageURL":"https://avatars.githubusercontent.com/u/1463944?s=200&v=4","key":"codeacademy"},{"name":"\u0110\u1ee9c Nguy\u1ec5n","title":"Developer, Translator","url":"https://github.com/ducnguyen96","imageURL":"https://avatars.githubusercontent.com/u/47471616?v=4","key":"ducnguyen96"}],"frontMatter":{"title":"What is REST","authors":["codeacademy","ducnguyen96"],"tags":["REST","API","HTTP","Web","Web Development","Web Services"],"hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"Different approaches to HTTP routing in Go","permalink":"/en/blog/2023/go-routing"},"nextItem":{"title":"V\u1ec1 Concurrency trong Go HTTP Servers","permalink":"/en/blog/2019/on-concurrency-in-go-http-servers"}},"content":"## Sources\\n\\n- https://www.codecademy.com/articles/what-is-rest"},{"id":"/2019/on-concurrency-in-go-http-servers","metadata":{"permalink":"/en/blog/2019/on-concurrency-in-go-http-servers","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2019/on-concurrency-in-go-http-servers.md","source":"@site/blog/2019/on-concurrency-in-go-http-servers.md","title":"V\u1ec1 Concurrency trong Go HTTP Servers","description":"V\u1ec1 Concurrency trong Go HTTP Servers","date":"2023-12-13T08:07:51.000Z","formattedDate":"December 13, 2023","tags":[{"label":"go","permalink":"/en/blog/tags/go"},{"label":"backend","permalink":"/en/blog/tags/backend"},{"label":"http","permalink":"/en/blog/tags/http"},{"label":"server","permalink":"/en/blog/tags/server"},{"label":"concurrency","permalink":"/en/blog/tags/concurrency"},{"label":"goroutine","permalink":"/en/blog/tags/goroutine"},{"label":"channel","permalink":"/en/blog/tags/channel"},{"label":"buffered channel","permalink":"/en/blog/tags/buffered-channel"},{"label":"unbuffered channel","permalink":"/en/blog/tags/unbuffered-channel"},{"label":"select","permalink":"/en/blog/tags/select"},{"label":"mutex","permalink":"/en/blog/tags/mutex"},{"label":"semaphore","permalink":"/en/blog/tags/semaphore"},{"label":"waitgroup","permalink":"/en/blog/tags/waitgroup"},{"label":"context","permalink":"/en/blog/tags/context"},{"label":"context cancellation","permalink":"/en/blog/tags/context-cancellation"},{"label":"context timeout","permalink":"/en/blog/tags/context-timeout"},{"label":"context deadline","permalink":"/en/blog/tags/context-deadline"}],"readingTime":8.69,"hasTruncateMarker":false,"authors":[{"name":"Eli Bendersky","title":"Developer","url":"https://eli.thegreenplace.net","imageURL":"https://avatars.githubusercontent.com/u/1130906?v=4","key":"eliben"},{"name":"\u0110\u1ee9c Nguy\u1ec5n","title":"Developer, Translator","url":"https://github.com/ducnguyen96","imageURL":"https://avatars.githubusercontent.com/u/47471616?v=4","key":"ducnguyen96"}],"frontMatter":{"title":"V\u1ec1 Concurrency trong Go HTTP Servers","description":"V\u1ec1 Concurrency trong Go HTTP Servers","authors":["eliben","ducnguyen96"],"tags":["go","backend","http","server","concurrency","goroutine","channel","buffered channel","unbuffered channel","select","mutex","semaphore","waitgroup","context","context cancellation","context timeout","context deadline"],"hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"What is REST","permalink":"/en/blog/2023/what-is-rest"},"nextItem":{"title":"Better HTTP Server Routing in Go 1.22","permalink":"/en/blog/2023/better-http-server-routing-in-go-122"}},"content":"Package c\xf3 s\u1eb5n `net/http` c\u1ee7a Go r\u1ea5t ti\u1ec7n l\u1ee3i v\xe0 hi\u1ec7u n\u0103ng cao, n\xf3 gi\xfap vi\u1ec7c ph\xe1t tri\u1ec3n c\u1ea3 web servers tr\u1edf n\xean d\u1ec5 d\xe0ng h\u01a1n. \u0110\u1ec3 \u0111\u1ea1t \u0111\u01b0\u1ee3c hi\u1ec7u n\u0103ng t\u1ed1t th\xec `net/http` s\u1eed d\u1ee5ng concurrency; m\u1eb7c d\xf9 \u0111\xfang th\u1eadt l\xe0 n\xf3 \u0111em l\u1ea1i hi\u1ec7u n\u0103ng r\u1ea5t t\u1ed1t tuy nhi\xean c\u0169ng k\xe8m theo m\u1ed9t s\u1ed1 v\u1ea5n \u0111\u1ec1. Ta s\u1ebd t\xecm hi\u1ec3u v\u1ec1 trong b\xe0i vi\u1ebft n\xe0y.\\n\\n## \u0110\u1ea3m b\u1ea3o handlers truy c\u1eadp \u0111\u1ed3ng th\u1eddi v\xe0o data m\u1ed9t kh\xe1c an to\xe0n\\n\\nB\u1eaft \u0111\u1ea7u b\u1eb1ng m\u1ed9t v\xed d\u1ee5 \u0111\u01a1n gi\u1ea3n - m\u1ed9t HTTP server cho m\u1ed9t b\u1ea3ng \u0111\u1ebfm - cho ph\xe9p user truy c\u1eadp. Ta c\xf3 th\u1ec3 t\u1ea1o counters (ho\u1eb7c set gi\xe1 tr\u1ecb c\u1ee7a nh\u1eefng counters \u0111ang t\u1ed3n t\u1ea1i) b\u1eb1ng query `set?name=N&val=V`, l\u1ea5y gi\xe1 tr\u1ecb c\u1ee7a ch\xfang b\u1eb1ng query `get?name=N` v\xe0 t\u0103ng gi\xe1 tr\u1ecb v\u1edbi query `inc?name=N`.\\n\\n\u0110\xe2y l\xe0 m\u1ed9t v\xed d\u1ee5 c\xe1ch user t\u01b0\u01a1ng t\xe1c v\u1edbi server:\\n\\n```bash\\n$ curl \\"localhost:8000/set?name=x&val=0\\"\\nok\\n$ curl \\"localhost:8000/get?name=x\\"\\nx: 0\\n$ curl \\"localhost:8000/inc?name=x\\"\\nok\\n$ curl \\"localhost:8000/get?name=x\\"\\nx: 1\\n```\\n\\nV\xe0 \u0111\xe2y l\xe0 m\u1ed9t server c\u01a1 b\u1ea3n c\xf3 c\xe1c ch\u1ee9c n\u0103ng tr\xean:\\n\\n```go\\npackage main\\n\\nimport (\\n  \\"fmt\\"\\n  \\"log\\"\\n  \\"net/http\\"\\n  \\"os\\"\\n  \\"strconv\\"\\n)\\n\\ntype CounterStore struct {\\n  counters map[string]int\\n}\\n\\nfunc (cs CounterStore) get(w http.ResponseWriter, req *http.Request) {\\n  log.Printf(\\"get %v\\", req)\\n  name := req.URL.Query().Get(\\"name\\")\\n  if val, ok := cs.counters[name]; ok {\\n    fmt.Fprintf(w, \\"%s: %d\\\\n\\", name, val)\\n  } else {\\n    fmt.Fprintf(w, \\"%s not found\\\\n\\", name)\\n  }\\n}\\n\\nfunc (cs CounterStore) set(w http.ResponseWriter, req *http.Request) {\\n  log.Printf(\\"set %v\\", req)\\n  name := req.URL.Query().Get(\\"name\\")\\n  val := req.URL.Query().Get(\\"val\\")\\n  intval, err := strconv.Atoi(val)\\n  if err != nil {\\n    fmt.Fprintf(w, \\"%s\\\\n\\", err)\\n  } else {\\n    cs.counters[name] = intval\\n    fmt.Fprintf(w, \\"ok\\\\n\\")\\n  }\\n}\\n\\nfunc (cs CounterStore) inc(w http.ResponseWriter, req *http.Request) {\\n  log.Printf(\\"inc %v\\", req)\\n  name := req.URL.Query().Get(\\"name\\")\\n  if _, ok := cs.counters[name]; ok {\\n    cs.counters[name]++\\n    fmt.Fprintf(w, \\"ok\\\\n\\")\\n  } else {\\n    fmt.Fprintf(w, \\"%s not found\\\\n\\", name)\\n  }\\n}\\n\\nfunc main() {\\n  store := CounterStore{counters: map[string]int{\\"i\\": 0, \\"j\\": 0}}\\n  http.HandleFunc(\\"/get\\", store.get)\\n  http.HandleFunc(\\"/set\\", store.set)\\n  http.HandleFunc(\\"/inc\\", store.inc)\\n\\n  portnum := 8000\\n  if len(os.Args) > 1 {\\n    portnum, _ = strconv.Atoi(os.Args[1])\\n  }\\n  log.Printf(\\"Going to listen on port %d\\\\n\\", portnum)\\n  log.Fatal(http.ListenAndServe(\\"localhost:\\"+strconv.Itoa(portnum), nil))\\n}\\n```\\n\\n\u0110o\u1ea1n code tr\xean r\u1ea5t \u0111\u01a1n gi\u1ea3n, qu\xe1 \u0111\u01a1n gi\u1ea3n, \u0111\u01a1n gi\u1ea3n \u0111\u1ebfn m\u1ee9c sai \ud83d\ude02. Ta \u0111\xe3 s\u1eed d\u1ee5ng `curl` theo tr\xecnh t\u1ef1, t\u1eebng request m\u1ed9t. V\u1ea5n \u0111\u1ec1 x\u1ea3y ra khi xu\u1ea5t hi\u1ec7n c\xe1c connection \u0111\u1ed3ng th\u1eddi. C\xf3 m\u1ed9t c\xe1ch \u0111\u1ec3 gi\u1ea3 l\u1eadp concurrent connections l\xe0 s\u1eed d\u1ee5ng [ApacheBench](https://en.wikipedia.org/wiki/ApacheBench):\\n\\n```bash\\n$ ab -n 20000 -c 200 \\"127.0.0.1:8000/inc?name=i\\"\\n\\nBenchmarking 127.0.0.1 (be patient)\\nCompleted 2000 requests\\nCompleted 4000 requests\\n\\nTest aborted after 10 failures\\n\\napr_socket_connect(): Connection reset by peer (104)\\nTotal of 4622 requests completed\\n```\\n\\nOops... \u0111i\u1ec1u g\xec x\u1ea3y ra v\u1eady? H\xe3y check logs c\u1ee7a server, ta s\u1ebd th\u1ea5y :\\n\\n```bash\\n<normal server logs>\\nfatal error: concurrent map writes\\n\\ngoroutine 6118 [running]:\\nruntime.throw(0x6b0a5c, 0x15)\\n  /usr/local/go/src/runtime/panic.go:608 +0x72 fp=0xc00060dba8 sp=0xc00060db78 pc=0x42ba12\\n```\\n\\nHandler c\u1ee7a ch\xfang ta c\xf3 th\u1ec3 ch\u1ea1y concurrently nh\u01b0ng ch\xfang \u0111\u1ec1u \u0111ang c\u1ed1 g\u1eafng thay \u0111\u1ed5i `CounterStore`. \u0110i\u1ec1u n\xe0y d\u1eabn t\u1edbi _race condition_ v\xec trong [Go, map operations are not atomic](https://golang.org/doc/faq#atomic_maps). May m\u1eafn l\xe0 Go runtime ph\xe1t hi\u1ec7n ra \u0111i\u1ec1u n\xe0y v\xe0 d\u1eebng l\u1ea1i v\u1edbi m\u1ed9t th\xf4ng b\xe1o h\u1eefu \xedch; n\u1ebfu d\u1eef li\u1ec7u b\u1ecb thay \u0111\u1ed5i m\xe0 kh\xf4ng c\xf3 th\xf4ng b\xe1o th\xec s\u1ebd t\u1ec7 h\u01a1n nhi\u1ec1u.\\n\\nGi\u1ea3i ph\xe1p \u0111\u01a1n gi\u1ea3n nh\u1ea5t l\xe0 tu\u1ea7n t\u1ef1 h\xf3a c\xe1c truy c\u1eadp \u0111\u1ebfn map s\u1eed d\u1ee5ng mutex.\\n\\nThe simplest solution is to serialize all map accesses using a mutex. D\u01b0\u1edbi \u0111\xe2y l\xe0 m\u1ed9t \u0111o\u1ea1n code tr\xedch t\u1eeb [v\xed d\u1ee5 ho\xe0n ch\u1ec9nh](https://github.com/ducnguyen96/ducnguyen96.github.io/tree/master/static/code/blog/gohttpconcurrency/mutex-server.go):\\n\\n```go\\ntype CounterStore struct {\\n  sync.Mutex\\n  counters map[string]int\\n}\\n\\nfunc (cs *CounterStore) inc(w http.ResponseWriter, req *http.Request) {\\n  log.Printf(\\"inc %v\\", req)\\n  cs.Lock()\\n  defer cs.Unlock()\\n  name := req.URL.Query().Get(\\"name\\")\\n  if _, ok := cs.counters[name]; ok {\\n    cs.counters[name]++\\n    fmt.Fprintf(w, \\"ok\\\\n\\")\\n  } else {\\n    fmt.Fprintf(w, \\"%s not found\\\\n\\", name)\\n  }\\n}\\n```\\n\\nC\xf3 2 thay \u0111\u1ed5i c\u1ea7n ch\xfa \xfd:\\n\\n1. ch\xfang ta nh\xfang `sync.Mutex` v\xe0o `CounterStore`, m\u1ed7i handler b\u1eaft \u0111\u1ea7u b\u1eb1ng vi\u1ec7c lock mutex v\xe0 defer unlock.\\n2. Thay \u0111\u1ed5i h\xe0m `inc` s\u1eed d\u1ee5ng pointer `*CounterStore` - c\xe1c methods thay \u0111\u1ed5i d\u1eef li\u1ec7u lu\xf4n n\xean \u0111\u01b0\u1ee3c defined v\u1edbi pointer receivers. Pointers receivers l\xe0 m\u1ed9t ph\u1ea7n [c\u1ef1c k\u1ef3 quan tr\u1ecdng khi s\u1eed d\u1ee5ng mutexes](/blog/2018/beware-of-copying-mutexes-in-go).\\n\\nCh\u1ea1y l\u1ea1i `ab` benchmark ta s\u1ebd th\u1ea5y race condition kh\xf4ng c\xf2n n\u1eefa, server \u0111\xe3 \u0111\u01b0\u1ee3c fixed.\\n\\n## \u0110\u1ed3ng b\u1ed9 h\xf3a s\u1eed d\u1ee5ng channels so v\u1edbi s\u1eed d\u1ee5ng mutexes\\n\\n\u0110\u1ed1i v\u1edbi nh\u1eefng l\u1eadp tr\xecnh vi\xean c\xf3 kinh nghi\u1ec7m th\xec vi\u1ec7c th\xeam mutex \u0111\u1ec3 \u0111\u1ed3ng b\u1ed9 h\xf3a truy c\u1eadp t\u1edbi `CounterStore` l\xe0 m\u1ed9t gi\u1ea3i ph\xe1p \u0111\u01b0\u01a1ng nhi\xean. Tuy nhi\xean m\u1ed9t trong nh\u1eefng kh\u1ea9u hi\u1ec7u c\u1ee7a Go l\xe0 _\\"Chia s\u1ebb b\u1ed9 nh\u1edb b\u1eb1ng c\xe1ch giao ti\u1ebfp, \u0111\u1eebng giao ti\u1ebfp b\u1eb1ng c\xe1ch chia s\u1ebb d\u1eef li\u1ec7u\\"_, li\u1ec7u c\xf3 \xe1p d\u1ee5ng \u1edf \u0111\xe2y ?\\n\\nThay v\xec s\u1eed d\u1ee5ng mutexes th\xec ta c\xf3 th\u1ec3 d\xf9ng channels \u0111\u1ec3 \u0111\u1ed3ng b\u1ed9 h\xf3a truy c\u1eadp \u0111\u1ebfn d\u1eef li\u1ec7u \u0111\u01b0\u1ee3c chia s\u1ebb. [Code m\u1eabu n\xe0y](https://github.com/ducnguyen96/ducnguyen96.github.io/tree/master/static/code/blog/gohttpconcurrency/channel-manager-server.go) thay th\u1ebf mutexes b\u1eb1ng channels. B\u1eaft \u0111\u1ea7u b\u1eb1ng vi\u1ec7c define m\u1ed9t \\"counter manager\\" l\xe0 m\u1ed9t background goroutine truy c\u1eadp t\u1edbi m\u1ed9t closure - n\u01a1i l\u01b0u tr\u1eef data.\\n\\n```go\\ntype CommandType int\\n\\nconst (\\n  GetCommand = iota\\n  SetCommand\\n  IncCommand\\n)\\n\\ntype Command struct {\\n  ty        CommandType\\n  name      string\\n  val       int\\n  replyChan chan int\\n}\\n\\nfunc startCounterManager(initvals map[string]int) chan<- Command {\\n  counters := make(map[string]int)\\n  for k, v := range initvals {\\n    counters[k] = v\\n  }\\n\\n  cmds := make(chan Command)\\n\\n  go func() {\\n    for cmd := range cmds {\\n      switch cmd.ty {\\n      case GetCommand:\\n        if val, ok := counters[cmd.name]; ok {\\n          cmd.replyChan <- val\\n        } else {\\n          cmd.replyChan <- -1\\n        }\\n      case SetCommand:\\n        counters[cmd.name] = cmd.val\\n        cmd.replyChan <- cmd.val\\n      case IncCommand:\\n        if _, ok := counters[cmd.name]; ok {\\n          counters[cmd.name]++\\n          cmd.replyChan <- counters[cmd.name]\\n        } else {\\n          cmd.replyChan <- -1\\n        }\\n      default:\\n        log.Fatal(\\"unknown command type\\", cmd.ty)\\n      }\\n    }\\n  }()\\n  return cmds\\n}\\n```\\n\\nThay v\xec truy c\u1eadp tr\u1ef1c ti\u1ebfp v\xe0o map c\u1ee7a counters, handlers s\u1ebd g\u1eedi `Commands` t\u1edbi m\u1ed9t channel v\xe0 s\u1ebd nh\u1eadn \u0111\u01b0\u1ee3c ph\u1ea3n h\u1ed3i qua m\u1ed9t channel kh\xe1c.\\n\\nObject \u0111\u01b0\u1ee3c shared cho c\xe1c handlers b\xe2y gi\u1edd l\xe0 m\u1ed9t `Server`:\\n\\n```go\\ntype Server struct {\\n  cmds chan<- Command\\n}\\n```\\n\\nV\xe0 \u0111\xe2y l\xe0 `inc` handler:\\n\\n```go\\nfunc (s *Server) inc(w http.ResponseWriter, req *http.Request) {\\n  log.Printf(\\"inc %v\\", req)\\n  name := req.URL.Query().Get(\\"name\\")\\n  replyChan := make(chan int)\\n  s.cmds <- Command{ty: IncCommand, name: name, replyChan: replyChan}\\n\\n  reply := <-replyChan\\n  if reply >= 0 {\\n    fmt.Fprintf(w, \\"ok\\\\n\\")\\n  } else {\\n    fmt.Fprintf(w, \\"%s not found\\\\n\\", name)\\n  }\\n}\\n```\\n\\nM\u1ed7i handler s\u1ebd g\u1ecdi t\u1edbi manager m\u1ed9t c\xe1ch \u0111\u1ed3ng b\u1ed9; g\u1eedi `Command` s\u1ebd block v\xe0 handler s\u1ebd ti\u1ebfp t\u1ee5c ch\u1ea1y khi reply channel nh\u1eadn \u0111\u01b0\u1ee3c t\xedn hi\u1ec7u. Ch\xfa \xfd l\xe0 \u1edf \u0111\xe2y kh\xf4ng d\xf9ng mutex, ta c\xf3 th\u1ec3 lo\u1ea1i b\u1ecf \u0111\u01b0\u1ee3c mutex v\xec t\u1ea1i 1 th\u1eddi \u0111i\u1ec3m ch\u1ec9 c\xf3 1 goroutine duy nh\u1ea5t c\xf3 th\u1ec3 truy c\u1eadp data.\\n\\nM\u1eb7c d\xf9 tr\xf4ng c\xf3 v\u1ebb nh\u01b0 m\u1ed9t k\u1ef9 th\u1ee5\xe2t th\xfa v\u1ecb, \u0111\u1ed1i v\u1edbi v\xed d\u1ee5 c\u1ee7a ch\xfang ta th\xec d\xf9ng channels l\xe0 overkill. Tr\xean th\u1ef1c t\u1ebf th\xec vi\u1ec7c s\u1eed d\u1ee5ng channels nhi\u1ec1u qu\xe1 m\u1ee9c l\xe0 m\u1ed9t trong nh\u1eefng v\u1ea5n \u0111\u1ec1 th\u01b0\u1eddng g\u1eb7p \u1edf Go beginers. Tr\xedch t\u1eeb [Go Wiki entry](https://github.com/golang/go/wiki/MutexOrChannel):\\n\\n> M\u1ecdi v\u1ea5n \u0111\u1ec1 li\xean quan \u0111\u1ebfn locking \u0111\u1ec1u c\xf3 th\u1ec3 \u0111\u01b0\u1ee3c gi\u1ea3i quy\u1ebft b\u1eb1ng channels ho\u1eb7c locks.\\n>\\n> V\u1eady b\u1ea1n n\xean s\u1eed d\u1ee5ng c\xe1i n\xe0o?\\n>\\n> S\u1eed d\u1ee5ng c\xe1i n\xe0o \u0111\u01a1n gi\u1ea3n nh\u1ea5t.\\n\\nTh\u01b0\u1eddng th\xec mutexes \u0111\u01b0\u1ee3c preferred h\u01a1n \u0111\u1ec3 b\u1ea3o v\u1ec7 shared state v\xec mutex cho c\u1ea3m gi\xe1c t\u1ef1 nhi\xean h\u01a1n.\\n\\n## Gi\u1edbi h\u1ea1n s\u1ef1 truy c\u1eadp \u0111\u1ed3ng th\u1eddi gian server\\n\\nNgo\xe0i v\u1ea5n \u0111\u1ec1 \u0111\u1ed3ng b\u1ed9 th\xec m\u1ed9t v\u1ea5n \u0111\u1ec1 kh\xe1c l\xe0 overloading. Ch\u1eb3ng h\u1ea1n b\u1ea1n expose server cho internet v\xe0 kh\xf4ng c\xf3 b\u1ea5t c\u1ee9 bi\u1ec7n ph\xe1p b\u1ea3o v\u1ec7 n\xe0o th\xec server c\u1ee7a b\u1ea1n r\u1ea5t d\u1ec5 b\u1ecb \u0111\xe1nh s\u1eadp b\u1eb1ng DoS. \u0110i\u1ec1u n\xe0y c\xf3 c\u0169ng th\u1ec3 x\u1ea3y ra m\u1ed9t c\xe1ch kh\xf4ng ch\u1ee7 \xfd. Trong nh\u1eefng tr\u01b0\u1eddng h\u1ee3p nh\u01b0 v\u1eady th\xec s\u1eadp server l\xe0 kh\xf4ng th\u1ec3 tr\xe1nh kh\u1ecfi nh\u01b0ng n\xean tr\xe1nh h\u1eadu qu\u1ea3 nghi\xeam tr\u1ecdng.\\n\\n\u0110i\u1ec1u n\xe0y r\u1ea5t d\u1ec5 th\u1ef1c hi\u1ec7n trong Go, v\xe0 c\u0169ng c\xf3 nhi\u1ec1u c\xe1ch kh\xe1c nhau. M\u1ed9t trong nh\u1eefng c\xe1ch \u0111\u01a1n gi\u1ea3n nh\u1ea5t l\xe0 rate limiting - c\xf3 ngh\u0129a l\xe0 s\u1ebd h\u1ea1n ch\u1ebf s\u1ed1 l\u01b0\u1ee3ng connections \u0111\u1ed3ng th\u1eddi, ho\u1eb7c gi\u1edbi h\u1ea1n s\u1ed1 connections theo \u0111\u01a1n v\u1ecb th\u1eddi gian. V\u1edbi c\xe1ch ti\u1ebfp c\u1eadn th\u1ee9 nh\u1ea5t th\xec ta c\xf3 th\u1ec3 s\u1eed [middlewares](https://github.com/ducnguyen96/ducnguyen96.github.io/tree/master/static/code/blog/gohttpconcurrency/mutex-server-rate-limited.go)\\n\\n```go\\n// limitNumClients is HTTP handling middleware that ensures no more than\\n// maxClients requests are passed concurrently to the given handler f.\\nfunc limitNumClients(f http.HandlerFunc, maxClients int) http.HandlerFunc {\\n  // Counting semaphore using a buffered channel\\n  sema := make(chan struct{}, maxClients)\\n\\n  return func(w http.ResponseWriter, req *http.Request) {\\n    sema <- struct{}{}\\n    defer func() { <-sema }()\\n    f(w, req)\\n  }\\n}\\n```\\n\\nB\u1ecdc handler v\u1edbi middleware tr\xean\\n\\n```go\\n// Limit to max 10 connections for this handler.\\nhttp.HandleFunc(\\"/inc\\", limitNumClients(store.inc, 10))\\n```\\n\\n\u0110i\u1ec1u n\xe0y \u0111\u1ea3m b\u1ea3o r\u1eb1ng kh\xf4ng c\xf3 nhi\u1ec1u h\u01a1n 10 clients c\xf3 th\u1ec3 ch\u1ea1y `inc` m\u1ed9t c\xe1ch \u0111\u1ed3ng th\u1eddi [^1]. Vi\u1ec7c m\u1edf r\u1ed9ng v\xed d\u1ee5 tr\xean s\u1eed d\u1ee5ng m\u1ed9t channel duy nh\u1ea5t \u0111\u1ec3 h\u1ea1n ch\u1ebf truy c\u1eadp tr\xean nhi\u1ec1u handlers c\u0169ng kh\xf4ng qu\xe1 kh\xf3 kh\u0103n, ho\u1eb7c b\u1ea1n c\xf3 th\u1ec3 s\u1eed d\u1ee5ng m\u1ed9t gi\u1ea3i ph\xe1p h\u01a1i overkill h\u01a1n l\xe0 gi\u1edbi h\u1ea1n s\u1ed1 connections \u0111\u1ed3ng th\u1eddi \u1edf m\u1ee9c \u0111\u1ed9 listener s\u1eed d\u1ee5ng [netutil.LimitListener](https://godoc.org/golang.org/x/net/netutil#LimitListener).\\n\\nM\u1ed9t c\xe1ch ti\u1ebfp c\u1eadn kh\xe1c l\xe0 gi\u1edbi h\u1ea1n th\u1eddi gian. Thay v\xec \\"kh\xf4ng c\xf3 nhi\u1ec1u h\u01a1n 10 requests c\xf9ng th\u1eddi \u0111i\u1ec3m\\" th\xec ta s\u1eed d\u1ee5ng \\"kh\xf4ng c\xf3 nhi\u1ec1u h\u01a1n 1 request m\u1ed7i 50ms\\". Go cung c\u1ea5p cho ta m\u1ed9t channel \u0111\u1ec3 c\xf3 th\u1ec3 d\u1ec5 d\xe0ng th\u1ef1c hi\u1ec7n \u0111i\u1ec1u n\xe0y - `time.Tick`, c\xf3 th\u1ec3 xem v\xed d\u1ee5 [\u1edf \u0111\xe2y](https://gobyexample.com/rate-limiting)\\n\\n## Ph\u1ee5 l\u1ee5c: where net.http goes concurrent\\n\\nV\u1edbi nh\u1eefng ai mu\u1ed1n t\xecm hi\u1ec3u v\u1ec1 c\xe1ch m\xe0 `net/http` th\u1ef1c hi\u1ec7n concurrency th\xec c\xf3 th\u1ec3 xem code \u1edf https://golang.org/src/net/http/server.go \u0111\u1ec3 tham kh\u1ea3o.\\n\\n`ListenAndServe` s\u1ebd ch\u1ea1y `Serve` - th\u1eb1ng n\xe0y g\u1ecdi `Accept` trong m\u1ed9t v\xf2ng l\u1eb7p. `Accept` t\u01b0\u01a1ng t\u1ef1 v\u1edbi `accept` syscall trong socket, t\u1ea1o m\u1ed9t connection m\u1edbi khi m\xe0 c\xf3 client accepted, connection n\xe0y sau \u0111\xf3 \u0111\u01b0\u1ee3c s\u1eed d\u1ee5ng \u0111\u1ec3 t\u01b0\u01a1ng t\xe1c v\u1edbi client n\xf3 c\xf3 type l\xe0 `type conn` - l\xe0 m\u1ed9t private type ch\u1ee9a server state. H\xe0m `serve` sau \u0111\xf3 \u0111\u1ecdc d\u1eef li\u1ec7u c\u1ea7n thi\u1ebft v\xe0 ch\u1ea1y c\xe1c handlers \u0111\xe3 \u0111\u01b0\u1ee3c \u0111\u0103ng k\xfd tr\u01b0\u1edbc.\\n\\n`http.Server.Serve` g\u1ecdi `conn.serve` nh\u01b0 sau:\\n\\n```go\\ngo c.serve(ctx)\\n```\\n\\nConcurrency n\u1eb1m \u1edf \u0111\xe2y. T\u1eeb \u0111\xe2y tr\u1edf \u0111i th\xec c\xf3 1 goroutine ri\xeang s\u1ebd handle connection n\xe0y.\\n\\n## Sources\\n\\n- https://eli.thegreenplace.net/2019/on-concurrency-in-go-http-servers\\n\\n[^1]: For a somewhat more robust approach, we could `select` between grabbing the semaphore and request\'s `Context.Done()` channel, to ensure that cancelled requests don\'t take place in line for the semaphore. A full treatment of robust context handling it outside the scope of this post, however."},{"id":"/2023/better-http-server-routing-in-go-122","metadata":{"permalink":"/en/blog/2023/better-http-server-routing-in-go-122","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2023/better-http-server-routing-in-go-122.md","source":"@site/blog/2023/better-http-server-routing-in-go-122.md","title":"Better HTTP Server Routing in Go 1.22","description":"Sources","date":"2023-12-13T08:07:51.000Z","formattedDate":"December 13, 2023","tags":[{"label":"go","permalink":"/en/blog/tags/go"},{"label":"Networking Programming","permalink":"/en/blog/tags/networking-programming"}],"readingTime":0.02,"hasTruncateMarker":false,"authors":[{"name":"Eli Bendersky","title":"Developer","url":"https://eli.thegreenplace.net","imageURL":"https://avatars.githubusercontent.com/u/1130906?v=4","key":"eliben"},{"name":"\u0110\u1ee9c Nguy\u1ec5n","title":"Developer, Translator","url":"https://github.com/ducnguyen96","imageURL":"https://avatars.githubusercontent.com/u/47471616?v=4","key":"ducnguyen96"}],"frontMatter":{"title":"Better HTTP Server Routing in Go 1.22","authors":["eliben","ducnguyen96"],"tags":["go","Networking Programming"],"hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"V\u1ec1 Concurrency trong Go HTTP Servers","permalink":"/en/blog/2019/on-concurrency-in-go-http-servers"},"nextItem":{"title":"How to Parse a JSON Request Body in Go","permalink":"/en/blog/2023/how-to-properly-parse-a-json-request-body"}},"content":"## Sources\\n\\n- https://eli.thegreenplace.net/2023/better-http-server-routing-in-go-122/"},{"id":"/2023/how-to-properly-parse-a-json-request-body","metadata":{"permalink":"/en/blog/2023/how-to-properly-parse-a-json-request-body","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2023/how-to-properly-parse-a-json-request-body.md","source":"@site/blog/2023/how-to-properly-parse-a-json-request-body.md","title":"How to Parse a JSON Request Body in Go","description":"Sources","date":"2023-12-13T08:07:51.000Z","formattedDate":"December 13, 2023","tags":[],"readingTime":0.02,"hasTruncateMarker":false,"authors":[{"name":"Alex Edwards","title":"Developer","url":"https://www.alexedwards.net","imageURL":"https://avatars.githubusercontent.com/u/228149?v=4","key":"alexedwards"},{"name":"\u0110\u1ee9c Nguy\u1ec5n","title":"Developer, Translator","url":"https://github.com/ducnguyen96","imageURL":"https://avatars.githubusercontent.com/u/47471616?v=4","key":"ducnguyen96"}],"frontMatter":{"title":"How to Parse a JSON Request Body in Go","authors":["alexedwards","ducnguyen96"],"hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"Better HTTP Server Routing in Go 1.22","permalink":"/en/blog/2023/better-http-server-routing-in-go-122"},"nextItem":{"title":"Stored XSS (Cross Site Scripting) l\xe0 g\xec v\xe0 c\xe1ch ng\u0103n ch\u1eb7n","permalink":"/en/blog/what-is-stored-xss"}},"content":"## Sources\\n\\n- https://www.alexedwards.net/blog/how-to-properly-parse-a-json-request-body"},{"id":"what-is-stored-xss","metadata":{"permalink":"/en/blog/what-is-stored-xss","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/securities/2023-12-10-stored-xss.md","source":"@site/blog/securities/2023-12-10-stored-xss.md","title":"Stored XSS (Cross Site Scripting) l\xe0 g\xec v\xe0 c\xe1ch ng\u0103n ch\u1eb7n","description":"Cross Site Scripting(XSS) l\xe0 g\xec, c\xe1ch th\u1ee9c ho\u1ea1t \u0111\u1ed9ng ra sao v\xe0 c\xe1ch ng\u0103n ch\u1eb7n.","date":"2023-12-10T00:00:00.000Z","formattedDate":"December 10, 2023","tags":[{"label":"xss","permalink":"/en/blog/tags/xss"},{"label":"web","permalink":"/en/blog/tags/web"},{"label":"app","permalink":"/en/blog/tags/app"},{"label":"backend","permalink":"/en/blog/tags/backend"},{"label":"vulnerability","permalink":"/en/blog/tags/vulnerability"},{"label":"security","permalink":"/en/blog/tags/security"},{"label":"stored xss","permalink":"/en/blog/tags/stored-xss"}],"readingTime":3.95,"hasTruncateMarker":true,"authors":[{"name":"\u0110\u1ee9c Nguy\u1ec5n","title":"Developer, Translator","url":"https://github.com/ducnguyen96","imageURL":"https://avatars.githubusercontent.com/u/47471616?v=4","key":"ducnguyen96"}],"frontMatter":{"title":"Stored XSS (Cross Site Scripting) l\xe0 g\xec v\xe0 c\xe1ch ng\u0103n ch\u1eb7n","description":"Cross Site Scripting(XSS) l\xe0 g\xec, c\xe1ch th\u1ee9c ho\u1ea1t \u0111\u1ed9ng ra sao v\xe0 c\xe1ch ng\u0103n ch\u1eb7n.","slug":"what-is-stored-xss","authors":["ducnguyen96"],"tags":["xss","web","app","backend","vulnerability","security","stored xss"],"hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"How to Parse a JSON Request Body in Go","permalink":"/en/blog/2023/how-to-properly-parse-a-json-request-body"}},"content":"Stored XSS l\xe0 ki\u1ec3u t\u1ea5n c\xf4ng XSS nguy hi\u1ec3m nh\u1ea5t trong c\xe1c lo\u1ea1i XSS v\xec n\xf3 kh\xf4ng ch\u1ec9 t\xe1c \u0111\u1ed9ng \u0111\u1ebfn user t\u1ea1i th\u1eddi \u0111i\u1ec3m t\u1ea5n c\xf4ng m\xe0 n\xf3 s\u1ebd \u1ea3nh h\u01b0\u1edfng \u0111\u1ebfn t\u1ea5t c\u1ea3 user v\xec m\xe3 \u0111\u1ed9c \u0111\xe3 \u0111\u01b0\u1ee3c l\u01b0u \u1edf ph\xeda server n\xean b\u1ea5t c\u1ee9 user n\xe0o t\u01b0\u01a1ng t\xe1c v\u1edbi server \u0111\u1ec1u s\u1ebd b\u1ecb \u1ea3nh h\u01b0\u1edfng.\\n\\n\x3c!-- truncate --\x3e\\n\\n<article class=\\"prose max-w-none\\">\\n\\n## 1. Gi\u1ea3i th\xedch\\n\\nTrong t\u1ea5n c\xf4ng `Stored XSS`, c\xe1c trang web l\u01b0u tr\u1eef m\xe3 \u0111\u1ed9c trong database, file ho\u1eb7c b\u1ed9 nh\u1edb c\u1ee7a server.\\nKhi ng\u01b0\u1eddi d\xf9ng truy c\u1eadp trang web, m\xe3 \u0111\u1ed9c \u0111\u01b0\u1ee3c th\u1ef1c thi tr\xean tr\xecnh duy\u1ec7t c\u1ee7a h\u1ecd.\\n\u0110\xe2y l\xe0 m\u1ed9t lo\u1ea1i t\u1ea5n c\xf4ng XSS nguy hi\u1ec3m h\u01a1n so v\u1edbi Reflected XSS v\xec n\xf3 c\xf3 th\u1ec3 \u1ea3nh h\u01b0\u1edfng \u0111\u1ebfn nhi\u1ec1u ng\u01b0\u1eddi d\xf9ng c\xf9ng m\u1ed9t l\xfac.\\n\\n\u0110\u1ec3 th\u1ef1c hi\u1ec7n t\u1ea5n c\xf4ng `Stored XSS`, tin t\u1eb7c ch\u1ec9 c\u1ea7n x\xe1c \u0111\u1ecbnh l\u1ed7 h\u1ed5ng b\u1ea3o m\u1eadt ph\xeda backend cho ph\xe9p th\u1ef1c hi\u1ec7n c\xe1c request ch\u1ee9a m\xe3 \u0111\u1ed9c.\\nTh\u01b0\u1eddng th\xec c\xe1c l\u1ed7 h\u1ed5ng n\xe0y l\xe0 do vi\u1ec7c validate d\u1eef li\u1ec7u \u0111\u1ea7u v\xe0o kh\xf4ng \u0111\u1ea7y \u0111\u1ee7, ho\u1eb7c kh\xf4ng ki\u1ec3m tra d\u1eef li\u1ec7u \u0111\u1ea7u v\xe0o tr\u01b0\u1edbc khi l\u01b0u v\xe0o database.\\n\\nM\u1ed9t v\xe0i h\u1eadu qu\u1ea3 c\u1ee7a t\u1ea5n c\xf4ng `Stored XSS`:\\n\\n- **Session hijacking**: tin t\u1eb7c c\xf3 th\u1ec3 l\u1ea5y \u0111\u01b0\u1ee3c cookie c\u1ee7a ng\u01b0\u1eddi d\xf9ng, t\u1eeb \u0111\xf3 c\xf3 th\u1ec3 \u0111\u0103ng nh\u1eadp v\xe0o t\xe0i kho\u1ea3n c\u1ee7a ng\u01b0\u1eddi d\xf9ng.\\n- **Privilege escalation**: tin t\u1eb7c c\xf3 th\u1ec3 th\u1ef1c hi\u1ec7n c\xe1c h\xe0nh \u0111\u1ed9ng \u0111\u1ed9c h\u1ea1i v\u1edbi quy\u1ec1n c\u1ee7a ng\u01b0\u1eddi d\xf9ng.\\n- **Disclosure of sensitive information**: tin t\u1eb7c c\xf3 th\u1ec3 l\u1ea5y \u0111\u01b0\u1ee3c c\xe1c th\xf4ng tin nh\u1ea1y c\u1ea3m c\u1ee7a ng\u01b0\u1eddi d\xf9ng.\\n- **Installation of malware/Trojan programs**: tin t\u1eb7c c\xf3 th\u1ec3 c\xe0i \u0111\u1eb7t c\xe1c ph\u1ea7n m\u1ec1m \u0111\u1ed9c h\u1ea1i, virus, trojan v\xe0o m\xe1y t\xednh c\u1ee7a ng\u01b0\u1eddi d\xf9ng.\\n- **Redirecting users to trustworthy-looking phishing pages**: tin t\u1eb7c c\xf3 th\u1ec3 chuy\u1ec3n h\u01b0\u1edbng ng\u01b0\u1eddi d\xf9ng \u0111\u1ebfn c\xe1c trang web gi\u1ea3 m\u1ea1o \u0111\u1ec3 l\u1ea5y th\xf4ng tin \u0111\u0103ng nh\u1eadp c\u1ee7a ng\u01b0\u1eddi d\xf9ng.\\n- **Web content spoofing**: tin t\u1eb7c c\xf3 th\u1ec3 thay \u0111\u1ed5i n\u1ed9i dung c\u1ee7a trang web.\\n\\nKh\xe1c v\u1edbi c\xe1c lo\u1ea1i XSS kh\xe1c khi m\xe0 ng\u01b0\u1eddi d\xf9ng ph\u1ea3i \u0111\u0103ng nh\u1eadp t\u1ea1i th\u1eddi \u0111i\u1ec3m t\u1ea5n c\xf4ng th\xec m\u1edbi b\u1ecb d\xednh m\xe3 \u0111\u1ed9c. Trong Stored XSS th\xec m\xe3 \u0111\u1ed9c \u0111\u01b0\u1ee3c l\u01b0u tr\u1eef trong server v\xe0 \u0111\u01b0\u1ee3c th\u1ef1c thi b\u1edfi\\nbrowser c\u1ee7a t\u1ea5t c\u1ea3 user c\xf3 request \u0111\u1ebfn server, \u0111i\u1ec1u n\xe0y l\xe0m cho ki\u1ec3u t\u1ea5n c\xf4ng n\xe0y nguy hi\u1ec3m h\u01a1n nhi\u1ec1u.\\n\\n## 2. Stored XSS payloads\\n\\nLo\u1ea1i t\u1ea5n c\xf4ng n\xe0y th\u01b0\u1eddng nh\u1eafm v\xe0o nh\u1eefng inputs nh\u01b0 comments tr\xean blog hay username, etc.\\n\\nM\u1ed9t s\u1ed1 lo\u1ea1i payload th\u01b0\u1eddng \u0111\u01b0\u1ee3c s\u1eed d\u1ee5ng:\\n\\n### 2.1. Polyglot-Based XSS Payload\\n\\nKi\u1ec3u n\xe0y nh\u1eafm v\xe0o m\u1ed9t l\u1ed7 h\u1ed5ng trong polygot - m\u1ed9t framework cho ph\xe9p th\u1ef1c thi code trong nhi\u1ec1u context trong raw form. M\u1ed9t polyglot XSS script th\u01b0\u1eddng s\u1ebd tr\xf4ng nh\u01b0 sau:\\n\\n### 2.2. Image XSS\\n\\nPayload n\xe0y cho ph\xe9p th\u1ef1c thi Javascript trong context c\u1ee7a m\u1ed9t `image`. Hacker th\u01b0\u1eddng s\u1eed d\u1ee5ng c\xe1ch n\xe0y \u0111\u1ec3 th\u1ef1c hi\u1ec7n c\xe1c h\xe0nh vi \u0111\u1ed9c h\u1ea1i tr\xean c\xe1c trang nh\u01b0 user profile hay c\xe1c \u0111\u01b0\u1eddng link \u1ea3nh kh\xe1c.\\nLo\u1ea1i n\xe0y s\u1ebd tr\xf4ng nh\u01b0 sau:\\n\\n```html\\n<img src=\\"javascript:alert(\'XSS\');\\" />\\n```\\n\\n### 2.3. Bypassing HTML entity encoding\\n\\n```html\\n<img src=\'javascript:alert(\\"XSS\\")\' />\\n```\\n\\n### 2.4. Improper `img` tags\\n\\n```html\\n<IMG \\"\\"\\">\\n<script>\\n  alert(\\"XSS\\");\\n<\/script>\\n\\"\\\\>\\n```\\n\\n## 2. M\u1ed9t s\u1ed1 c\xe1ch hacker l\u1ee3i d\u1ee5ng l\u1ed7 h\u1ed5ng XSS\\n\\n### 2.1. Cookie Grabbing - tr\u1ed9m cookie\\n\\nHackers c\xf3 th\u1ec3 tr\u1ed9m cookie t\u1eeb m\u1ed9t ng\u01b0\u1eddi d\xf9ng \u0111\xe3 login v\xe0 \u0111\xe3 \u0111\u01b0\u1ee3c x\xe1c th\u1ef1c(authenticated). \u0110\u1ec3 l\xe0m \u0111\u01b0\u1ee3c \u0111i\u1ec1u n\xe0y th\xec hacker ch\u1ec9 c\u1ea7n th\xeam \u0111o\u1ea1n code d\u01b0\u1edbi \u0111\xe2y v\xe0o b\u1ea5t c\u1ee9 ch\u1ed7 n\xe0o c\xf3 user input,\\nch\u1eb3ng h\u1ea1n nh\u01b0 user profiles, tin nh\u1eafn, forums, etc.\\n\\n```html\\n<script type=\\"text/javascript\\">\\n  var adr = \\"../evil.php?cakemonster=\\" + escape(document.cookie);\\n<\/script>\\n```\\n\\n\u0110o\u1ea1n code tr\xean s\u1ebd th\u1ef1c thi vi\u1ec7c vi\u1ebft cookie v\xe0o file **evil.php** - n\u01a1i m\xe0 hacker c\xf3 th\u1ec3 check l\u1ea1i k\u1ebft qu\u1ea3 c\u1ee7a \u0111o\u1ea1n m\xe3.\\n\\n### 2.2. Thao t\xfang page\\n\\nHacker c\u0169ng c\xf3 th\u1ec3 nh\u1eafm v\xe0o c\xe1c error messages ch\u1eb3ng h\u1ea1n nh\u01b0 trang 404.\\n\\n```html\\n<html>\\n  <body>\\n    <? php\\nprint \\"Not found:\\". urldecode($_SERVER[\\"REQUEST_URI\\"]);\\n?>\\n  </body>\\n</html>\\n```\\n\\nN\u1ebfu user click v\xe0o m\u1ed9t trang kh\xf4ng t\u1ed3n t\u1ea1i ch\u1eb3ng h\u1ea1n nh\u01b0 **https://example.com/non_existent_file** th\xec s\u1ebd nh\u1eadn \u0111\u01b0\u1ee3c response l\xe0 **Not found: /non_existent_file**\\n\\nHackers c\xf3 th\u1ec3 thao t\xfang trang error n\xe0y \u0111\u1ec3 th\xeam v\xe0o 1 \u0111o\u1ea1n m\xe3 \u0111\u1ed9c ch\u1eb3ng h\u1ea1n **https://example.com/<script>alert(\'test\');<\/script>**, b\xe2y gi\u1edd m\u1ed7i khi user truy c\u1eadp v\xe0o 1 trang kh\xf4ng t\u1ed3n t\u1ea1i th\xec s\u1ebd \u0111\u01b0\u1ee3c ph\u1ea3n h\u1ed3i b\u1eb1ng trang 404 nh\u01b0ng gi\u1edd trang 404 \u1ea5y \u0111\xe3 k\xe8m theo m\xe3 \u0111\u1ed9c.\\n\\n## 3. Ng\u0103n ch\u1eb7n l\u1ed7 h\u1ed5ng Stored XSS\\n\\n- Th\u1ef1c hi\u1ec7n validate input \u0111\xfang c\xe1ch\\n\\n- S\u1eed d\u1ee5ng scanner \u0111\u1ec3 ph\xe1t hi\u1ec7n l\u1ed7 h\u1ed5ng b\u1ea3o m\u1eadt\\n\\n- S\u1eed d\u1ee5ng `Content Security Policy` (CSP)\\n\\n- `Escape` c\xe1c n\u1ed9i dung \u0111\u1ed9ng, kh\xf4ng cho ph\xe9p user submit raw HTML \u1edf c\xe1c inputs.\\n\\n</article>"}]}')}}]);